{
  "name": "Studley.ai Clone",
  "description": "A comprehensive AI study assistant. Upload PDFs to generate deep study notes, interactive quizzes, and chat with your documents using Google Gemini. Features a mock backend for instant preview."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  email: string;
  name: string;
}

export interface Document {
  id: string;
  title: string;
  uploadDate: string;
  fileData: string; // Base64 string
  mimeType: string;
  size: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Note {
  id: string;
  documentId: string;
  title: string;
  content: string; // Markdown content
  createdAt: string;
}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctAnswerIndex: number;
  explanation: string;
}

export interface Quiz {
  id: string;
  documentId: string;
  title: string;
  questions: QuizQuestion[];
  createdAt: string;
}

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  CHAT = 'CHAT',
  NOTES = 'NOTES',
  QUIZ = 'QUIZ',
}

export interface AppState {
  user: User | null;
  currentView: AppView;
  activeDocumentId: string | null;
}

import { User, Document, Note, Quiz, ChatMessage } from '../types';

// Keys for LocalStorage
const KEYS = {
  USER: 'studley_user',
  DOCS: 'studley_docs',
  NOTES: 'studley_notes',
  QUIZZES: 'studley_quizzes',
  CHATS: 'studley_chats',
};

// --- User / Auth ---
export const loginUser = async (email: string, name: string): Promise<User> => {
  // Simulate API delay
  await new Promise(resolve => setTimeout(resolve, 500));
  const user: User = { id: 'user-1', email, name };
  localStorage.setItem(KEYS.USER, JSON.stringify(user));
  return user;
};

export const logoutUser = () => {
  localStorage.removeItem(KEYS.USER);
};

export const getCurrentUser = (): User | null => {
  const stored = localStorage.getItem(KEYS.USER);
  return stored ? JSON.parse(stored) : null;
};

// --- Documents ---
export const saveDocument = async (file: File): Promise<Document> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const base64String = reader.result as string;
      // Remove data URL prefix for cleaner storage if needed, but keeping it helps for display
      // For Gemini, we often need just the base64 part, so we'll strip it in the service

      const newDoc: Document = {
        id: crypto.randomUUID(),
        title: file.name,
        uploadDate: new Date().toISOString(),
        fileData: base64String,
        mimeType: file.type,
        size: file.size
      };

      const docs = getDocuments();
      docs.push(newDoc);
      localStorage.setItem(KEYS.DOCS, JSON.stringify(docs));
      resolve(newDoc);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const getDocuments = (): Document[] => {
  const stored = localStorage.getItem(KEYS.DOCS);
  return stored ? JSON.parse(stored) : [];
};

export const getDocumentById = (id: string): Document | undefined => {
  return getDocuments().find(d => d.id === id);
};

export const deleteDocument = (id: string) => {
  const docs = getDocuments().filter(d => d.id !== id);
  localStorage.setItem(KEYS.DOCS, JSON.stringify(docs));
};

// --- Notes ---
export const saveNote = (note: Note) => {
  const notes = getNotes();
  const existingIndex = notes.findIndex(n => n.id === note.id);
  if (existingIndex >= 0) {
    notes[existingIndex] = note;
  } else {
    notes.push(note);
  }
  localStorage.setItem(KEYS.NOTES, JSON.stringify(notes));
};

export const getNotes = (): Note[] => {
  const stored = localStorage.getItem(KEYS.NOTES);
  return stored ? JSON.parse(stored) : [];
};

export const getNotesByDocumentId = (docId: string): Note[] => {
  return getNotes().filter(n => n.documentId === docId);
};

// --- Quizzes ---
export const saveQuiz = (quiz: Quiz) => {
  const quizzes = getQuizzes();
  quizzes.push(quiz);
  localStorage.setItem(KEYS.QUIZZES, JSON.stringify(quizzes));
};

export const getQuizzes = (): Quiz[] => {
  const stored = localStorage.getItem(KEYS.QUIZZES);
  return stored ? JSON.parse(stored) : [];
};

export const getQuizzesByDocumentId = (docId: string): Quiz[] => {
  return getQuizzes().filter(q => q.documentId === docId);
};

// --- Chats ---
export const saveChatMessage = (docId: string, message: ChatMessage) => {
  const allChats = getAllChats();
  if (!allChats[docId]) {
    allChats[docId] = [];
  }
  allChats[docId].push(message);
  localStorage.setItem(KEYS.CHATS, JSON.stringify(allChats));
};

export const getChatHistory = (docId: string): ChatMessage[] => {
  const allChats = getAllChats();
  return allChats[docId] || [];
};

const getAllChats = (): Record<string, ChatMessage[]> => {
  const stored = localStorage.getItem(KEYS.CHATS);
  return stored ? JSON.parse(stored) : {};
};

import { GoogleGenAI, Type } from "@google/genai";
import { Document, Quiz, Note } from '../types';

// Helper to get fresh API client
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to prepare file part
const getFilePart = (doc: Document) => {
  // strip "data:application/pdf;base64," prefix if present
  const base64Data = doc.fileData.split(',')[1] || doc.fileData;
  return {
    inlineData: {
      mimeType: doc.mimeType,
      data: base64Data
    }
  };
};

export const generateChatResponse = async (
  doc: Document,
  history: { role: string; text: string }[],
  newMessage: string
): Promise<string> => {
  const ai = getAiClient();
  const filePart = getFilePart(doc);

  // We use flash for chat for lower latency
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are a helpful study assistant AI for the "Studley.ai" platform.
    Your task is to answer questions based ONLY on the provided document.
    - Explain concepts clearly and simply.
    - Expand ideas instead of summarizing them.
    - Use examples where helpful.
    - NEVER hallucinate or use outside knowledge.
    - If the answer is not found in the document, respond exactly with: "I couldn’t find this in your notes."
  `;

  try {
    const contents = [
      { role: 'user', parts: [filePart, { text: "Analyze this document for our session." }] },
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: newMessage }] }
    ];

    const response = await ai.models.generateContent({
      model,
      contents: contents, // history + new message
      config: {
        systemInstruction,
        temperature: 0.4,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

export const generateStudyNotes = async (doc: Document): Promise<Note> => {
  const ai = getAiClient();
  const filePart = getFilePart(doc);
  const model = "gemini-3-pro-preview"; // Use Pro for higher quality reasoning/formatting

  const prompt = `
    Generate deep, well-structured study notes from this document.
    Do NOT just summarize.
    - Use clear headings and subheadings (Markdown).
    - Use bullet points for lists.
    - Include Definitions sections.
    - Include Examples sections.
    - Add a "Key Takeaways" section at the end.
    - Notes should feel like high-quality handwritten or textbook notes.
    - Expand concepts clearly.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        temperature: 0.3, // Lower temp for more factual/structured output
      }
    });

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `Study Notes: ${doc.title}`,
      content: response.text || "Failed to generate notes.",
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Notes Error:", error);
    throw error;
  }
};

export const generateQuiz = async (doc: Document, difficulty: 'easy' | 'medium' | 'hard'): Promise<Quiz> => {
  const ai = getAiClient();
  const filePart = getFilePart(doc);
  const model = "gemini-3-flash-preview";

  const prompt = `
    Generate a quiz with 5 multiple choice questions based on the document.
    Difficulty: ${difficulty}.
    Return the output in strictly valid JSON format matching this schema:
    {
      "questions": [
        {
          "question": "string",
          "options": ["string", "string", "string", "string"],
          "correctAnswerIndex": number (0-3),
          "explanation": "string"
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  correctAnswerIndex: { type: Type.INTEGER },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswerIndex", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonText = response.text || "{}";
    const parsed = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)} Quiz: ${doc.title}`,
      questions: parsed.questions?.map((q: any) => ({...q, id: crypto.randomUUID()})) || [],
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Quiz Error:", error);
    throw error;
  }
};

import React from 'react';
import { BookOpen, MessageSquare, FileText, CheckSquare, LogOut, Menu, X, Plus } from 'lucide-react';
import { User, AppView } from '../types';

