  user, 
  currentView, 
  onNavigate, 
  onLogout, 
  children,
  onUploadClick
}) => {
  const [isSidebarOpen, setIsSidebarOpen] = React.useState(false);

  const navItems = [
    { view: AppView.DASHBOARD, icon: BookOpen, label: 'Dashboard' },
    { view: AppView.CHAT, icon: MessageSquare, label: 'AI Chat' },
    { view: AppView.NOTES, icon: FileText, label: 'Study Notes' },
    { view: AppView.QUIZ, icon: CheckSquare, label: 'Quizzes' },
