export default Layout;

import React, { useState } from 'react';
import { Sparkles, ArrowRight } from 'lucide-react';

interface AuthProps {
  onLogin: (email: string, name: string) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    // Simulate network request
    setTimeout(() => {
      onLogin(email, name || email.split('@')[0]);
      setLoading(false);
    }, 800);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 to-blue-100 p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md p-8 relative overflow-hidden">
        {/* Decor elements */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-bl-full -mr-10 -mt-10 z-0"></div>

        <div className="relative z-10">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-indigo-600 rounded-2xl mx-auto flex items-center justify-center mb-4 shadow-lg shadow-indigo-200">
              <Sparkles className="text-white w-8 h-8" />
            </div>
            <h1 className="text-2xl font-bold text-gray-900">Welcome to Studley.ai</h1>
            <p className="text-gray-500 mt-2">Your intelligent study companion</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {!isLogin && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                <input
                  type="text"
                  required
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                  placeholder="John Doe"
                />
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                placeholder="you@example.com"
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 px-4 rounded-lg shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed mt-6"
            >
              {loading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  {isLogin ? 'Sign In' : 'Create Account'}
                  <ArrowRight size={18} />
                </>
              )}
            </button>
          </form>

          <div className="mt-6 text-center">
            <button
              onClick={() => setIsLogin(!isLogin)}
              className="text-sm text-indigo-600 hover:text-indigo-800 font-medium"
            >
              {isLogin ? "Don't have an account? Sign up" : 'Already have an account? Sign in'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useCallback, useState } from 'react';
import { Upload, FileText, CheckCircle, AlertCircle, X } from 'lucide-react';

interface DocumentUploadProps {
  onUpload: (file: File) => Promise<void>;
  onClose: () => void;
}

const DocumentUpload: React.FC<DocumentUploadProps> = ({ onUpload, onClose }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setIsDragging(true);
    } else if (e.type === 'dragleave') {
      setIsDragging(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      validateAndSetFile(e.dataTransfer.files[0]);
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      validateAndSetFile(e.target.files[0]);
    }
  };

  const validateAndSetFile = (file: File) => {
    if (file.type !== 'application/pdf') {
      setError('Please upload a valid PDF file.');
      return;
    }
    // Limit size to 10MB for this demo (LocalStorage limits)
    if (file.size > 10 * 1024 * 1024) {
      setError('File size too large. Please upload a file smaller than 10MB.');
      return;
    }
    setError(null);
    setFile(file);
  };

  const handleSubmit = async () => {
    if (!file) return;
    setUploading(true);
    try {
      await onUpload(file);
      onClose();
    } catch (err) {
      console.error(err);
      setError('Failed to process file. Please try again.');
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden relative">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 transition-colors"
        >
          <X size={24} />
        </button>

        <div className="p-8">
          <div className="text-center mb-6">
            <h2 className="text-2xl font-bold text-gray-900">Upload Study Material</h2>
            <p className="text-gray-500 mt-2">Upload your course PDF to get started.</p>
          </div>

          <div
            onDragEnter={handleDrag}
            onDragLeave={handleDrag}
            onDragOver={handleDrag}
            onDrop={handleDrop}
            className={`
              border-2 border-dashed rounded-xl p-8 text-center transition-all duration-200
              ${isDragging 
                ? 'border-indigo-500 bg-indigo-50' 
                : file 
                  ? 'border-green-500 bg-green-50' 
                  : 'border-gray-300 hover:border-indigo-400 hover:bg-gray-50'}
            `}
          >
            <input
              type="file"
              id="file-upload"
              className="hidden"
              accept=".pdf"
              onChange={handleChange}
            />

            {file ? (
              <div className="flex flex-col items-center">
                <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600">
                  <CheckCircle size={32} />
                </div>
                <p className="font-medium text-gray-900 truncate max-w-xs">{file.name}</p>
                <p className="text-sm text-gray-500 mt-1">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                <button 
                  onClick={() => setFile(null)}
                  className="text-xs text-red-500 font-medium mt-3 hover:underline"
                >
                  Remove file
                </button>
              </div>
            ) : (
              <div className="flex flex-col items-center">
                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mb-4 text-indigo-600">
                  <Upload size={32} />
                </div>
                <p className="font-medium text-gray-900">Drag & Drop or Click to Upload</p>
                <p className="text-sm text-gray-500 mt-1">PDFs only, up to 10MB</p>
                <label 
                  htmlFor="file-upload" 
                  className="mt-4 px-4 py-2 bg-white border border-gray-300 rounded-lg shadow-sm text-sm font-medium text-gray-700 hover:bg-gray-50 cursor-pointer"
                >
                  Select File
                </label>
              </div>
            )}
          </div>

          {error && (
            <div className="mt-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg flex items-center gap-2">
              <AlertCircle size={16} />
              {error}
            </div>
          )}

          <div className="mt-8 flex justify-end gap-3">
            <button
              onClick={onClose}
              className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors font-medium"
            >
              Cancel
            </button>
            <button
              onClick={handleSubmit}
              disabled={!file || uploading}
              className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg shadow-sm transition-all font-medium disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
              {uploading ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                  Processing...
                </>
              ) : (
                'Upload & Analyze'
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DocumentUpload;

import React, { useState, useEffect, useRef } from 'react';
import { Send, Bot, User as UserIcon, AlertCircle } from 'lucide-react';
import { Document, ChatMessage } from '../types';
import { generateChatResponse } from '../services/gemini';
import { saveChatMessage, getChatHistory } from '../services/storage';

interface ChatInterfaceProps {
  document: Document;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ document }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Load history
    const history = getChatHistory(document.id);
    setMessages(history);
  }, [document.id]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      text: input.trim(),
      timestamp: Date.now()
    };

    // Optimistic update
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    saveChatMessage(document.id, userMsg);
    setInput('');
    setIsLoading(true);

    try {
      // Prepare history for API (map internal type to API type simplified)
      const apiHistory = messages.map(m => ({ role: m.role, text: m.text }));

      const responseText = await generateChatResponse(document, apiHistory, userMsg.text);

      const aiMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      saveChatMessage(document.id, aiMsg);

    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: "Sorry, I encountered an error. Please check your API key or try again.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="p-4 border-b bg-gray-50 flex items-center justify-between">
        <h3 className="font-semibold text-gray-800 flex items-center gap-2">
          <Bot className="text-indigo-600" size={20} />
          Chatting with: <span className="text-indigo-600 truncate max-w-xs">{document.title}</span>
        </h3>
        <span className="text-xs text-gray-500 px-2 py-1 bg-white rounded border">Gemini Powered</span>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center text-gray-400 p-8">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
              <Bot size={32} />
            </div>
            <p className="text-lg font-medium text-gray-600">Ask me anything!</p>
            <p className="text-sm mt-2 max-w-md">
              I can explain concepts, summarize sections, or help you find specific information in your notes.
            </p>
          </div>
        ) : (
          messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              {msg.role === 'model' && (
                <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center flex-shrink-0 mt-1">
                  <Bot size={16} className="text-indigo-600" />
                </div>
              )}

              <div 
                className={`
                  max-w-[80%] rounded-2xl px-5 py-3 text-sm leading-relaxed shadow-sm
                  ${msg.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white border border-gray-200 text-gray-800 rounded-bl-none'}
                `}
              >
                {msg.text}
              </div>

              {msg.role === 'user' && (
                <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center flex-shrink-0 mt-1">
                  <UserIcon size={16} className="text-gray-600" />
                </div>
              )}
            </div>
          ))
        )}

        {isLoading && (
          <div className="flex gap-4 justify-start">
             <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center flex-shrink-0 mt-1">
                <Bot size={16} className="text-indigo-600" />
             </div>
             <div className="bg-white border border-gray-200 rounded-2xl rounded-bl-none px-5 py-4 shadow-sm">
                <div className="flex gap-1">
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 border-t bg-white">
        <form onSubmit={handleSend} className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask a question about your notes..."
            className="w-full pl-4 pr-12 py-3.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
          />
          <button 
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 top-2 p-1.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:bg-gray-400 transition-colors"
          >
            <Send size={20} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect } from 'react';
import { FileText, Sparkles, RefreshCw, Copy, Check } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Document, Note } from '../types';
import { generateStudyNotes } from '../services/gemini';
import { saveNote, getNotesByDocumentId } from '../services/storage';

interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const savedNotes = getNotesByDocumentId(document.id);
    setNotes(savedNotes);
    if (savedNotes.length > 0) {
      setActiveNote(savedNotes[0]);
    }
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const newNote = await generateStudyNotes(document);
      saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-[calc(100vh-140px)] flex gap-6">
      {/* Sidebar List */}
      <div className="w-64 flex-shrink-0 flex flex-col gap-4">
        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-3 px-4 rounded-xl shadow-sm transition-all font-medium disabled:opacity-70"
        >
          {isGenerating ? (
            <RefreshCw className="animate-spin" size={20} />
          ) : (
            <Sparkles size={20} />
          )}
          {isGenerating ? 'Generating...' : 'New Study Notes'}
        </button>

        <div className="flex-1 overflow-y-auto space-y-2 pr-2">
          {notes.length === 0 ? (
            <p className="text-sm text-gray-500 text-center py-4">No notes yet.</p>
          ) : (
            notes.map(note => (
              <button
                key={note.id}
                onClick={() => setActiveNote(note)}
                className={`w-full text-left p-3 rounded-lg border transition-all ${
                  activeNote?.id === note.id
                    ? 'bg-indigo-50 border-indigo-200 text-indigo-900'
                    : 'bg-white border-gray-200 text-gray-700 hover:border-indigo-200 hover:bg-gray-50'
                }`}
              >
                <div className="flex items-center gap-2 mb-1">
                  <FileText size={16} className={activeNote?.id === note.id ? "text-indigo-600" : "text-gray-400"} />
                  <span className="font-medium text-sm truncate">{new Date(note.createdAt).toLocaleDateString()}</span>
                </div>
                <p className="text-xs text-gray-500 truncate">{note.title}</p>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col overflow-hidden">
        {activeNote ? (
          <>
            <div className="p-4 border-b flex items-center justify-between bg-gray-50">
              <h2 className="font-semibold text-gray-900 truncate">{activeNote.title}</h2>
              <button 
                onClick={copyToClipboard}
                className="flex items-center gap-1.5 text-sm text-gray-600 hover:text-indigo-600 transition-colors px-3 py-1.5 rounded-lg hover:bg-white border border-transparent hover:border-gray-200"
              >
                {copied ? <Check size={16} /> : <Copy size={16} />}
                {copied ? 'Copied' : 'Copy Text'}
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 prose prose-indigo max-w-none">
              <ReactMarkdown 
                components={{
                   h1: ({node, ...props}) => <h1 className="text-2xl font-bold text-gray-900 mb-4 pb-2 border-b" {...props} />,
                   h2: ({node, ...props}) => <h2 className="text-xl font-semibold text-indigo-700 mt-6 mb-3" {...props} />,
                   h3: ({node, ...props}) => <h3 className="text-lg font-medium text-gray-800 mt-4 mb-2" {...props} />,
                   ul: ({node, ...props}) => <ul className="list-disc pl-5 space-y-2 mb-4" {...props} />,
                   li: ({node, ...props}) => <li className="text-gray-700 leading-relaxed" {...props} />,
                   strong: ({node, ...props}) => <strong className="font-semibold text-gray-900 bg-yellow-50 px-1 rounded" {...props} />,
                   blockquote: ({node, ...props}) => <blockquote className="border-l-4 border-indigo-300 pl-4 py-1 italic bg-indigo-50/50 my-4 rounded-r" {...props} />
                }}
              >
                {activeNote.content}
              </ReactMarkdown>
            </div>
          </>
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-gray-400">
            <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4">
              <FileText size={32} />
            </div>
            <p>Select a note or generate a new one.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default NotesGenerator;

import React, { useState, useEffect } from 'react';
import { CheckSquare, Play, HelpCircle, Check, X, RefreshCw, Trophy } from 'lucide-react';
import { Document, Quiz, QuizQuestion } from '../types';
import { generateQuiz } from '../services/gemini';
import { saveQuiz, getQuizzesByDocumentId } from '../services/storage';

interface QuizGeneratorProps {
  document: Document;
}

const QuizGenerator: React.FC<QuizGeneratorProps> = ({ document }) => {
  const [quizzes, setQuizzes] = useState<Quiz[]>([]);
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [difficulty, setDifficulty] = useState<'easy' | 'medium' | 'hard'>('medium');

  // Quiz Taking State
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [score, setScore] = useState(0);
  const [quizCompleted, setQuizCompleted] = useState(false);

  useEffect(() => {
    const saved = getQuizzesByDocumentId(document.id);
    setQuizzes(saved);
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const newQuiz = await generateQuiz(document, difficulty);
      saveQuiz(newQuiz);
      setQuizzes(prev => [newQuiz, ...prev]);
      startQuiz(newQuiz);
    } catch (error) {
      console.error(error);
      alert("Failed to generate quiz. Check API Key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const startQuiz = (quiz: Quiz) => {
    setActiveQuiz(quiz);
    setCurrentQuestionIndex(0);
    setSelectedAnswer(null);
    setShowExplanation(false);
    setScore(0);
    setQuizCompleted(false);
  };

  const handleAnswerSelect = (index: number) => {
    if (selectedAnswer !== null) return; // Prevent changing answer
    setSelectedAnswer(index);
    setShowExplanation(true);

    if (index === activeQuiz?.questions[currentQuestionIndex].correctAnswerIndex) {
      setScore(prev => prev + 1);
    }
  };

  const nextQuestion = () => {
    if (!activeQuiz) return;
    if (currentQuestionIndex < activeQuiz.questions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedAnswer(null);
      setShowExplanation(false);
    } else {
      setQuizCompleted(true);
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex gap-6">
       {/* Sidebar */}
       <div className="w-64 flex-shrink-0 flex flex-col gap-4">
         <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200">
           <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Difficulty</label>
           <select 
             value={difficulty}
             onChange={(e) => setDifficulty(e.target.value as any)}
             className="w-full p-2 bg-gray-50 border border-gray-200 rounded-lg text-sm mb-3 outline-none focus:ring-2 focus:ring-indigo-500"
           >
             <option value="easy">Easy</option>
             <option value="medium">Medium</option>
             <option value="hard">Hard</option>
           </select>
           <button
             onClick={handleGenerate}
             disabled={isGenerating}
             className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2 px-4 rounded-lg transition-all text-sm font-medium disabled:opacity-70"
           >
             {isGenerating ? <RefreshCw className="animate-spin" size={16} /> : <Play size={16} />}
             Generate Quiz
           </button>
         </div>

         <div className="flex-1 overflow-y-auto space-y-2 pr-2">
            <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider px-2">History</h3>
            {quizzes.length === 0 ? (
               <p className="text-sm text-gray-500 px-2">No quizzes yet.</p>
            ) : (
              quizzes.map(quiz => (
                <button
                  key={quiz.id}
                  onClick={() => startQuiz(quiz)}
                  className={`w-full text-left p-3 rounded-lg border transition-all ${
                    activeQuiz?.id === quiz.id
                      ? 'bg-indigo-50 border-indigo-200 text-indigo-900'
                      : 'bg-white border-gray-200 text-gray-700 hover:border-indigo-200 hover:bg-gray-50'
                  }`}
                >
                  <p className="text-sm font-medium truncate">{quiz.title}</p>
                  <p className="text-xs text-gray-500 mt-1">{quiz.questions.length} Questions</p>
                </button>
              ))
            )}
         </div>
       </div>

       {/* Quiz Area */}
       <div className="flex-1 bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col overflow-hidden relative">
         {!activeQuiz ? (
            <div className="flex flex-col items-center justify-center h-full text-gray-400">
              <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4">
                <CheckSquare size={32} />
              </div>
              <p>Generate a quiz to test your knowledge.</p>
            </div>
         ) : quizCompleted ? (
           <div className="flex flex-col items-center justify-center h-full p-8 animate-in fade-in duration-500">
             <div className="w-24 h-24 bg-yellow-100 text-yellow-600 rounded-full flex items-center justify-center mb-6 shadow-lg shadow-yellow-100">
               <Trophy size={48} />
             </div>
             <h2 className="text-3xl font-bold text-gray-900 mb-2">Quiz Completed!</h2>
             <p className="text-gray-500 mb-8">You scored {score} out of {activeQuiz.questions.length}</p>

             <div className="w-full max-w-md bg-gray-50 rounded-xl overflow-hidden mb-8">
               <div className="h-4 bg-gray-200">
                 <div 
                   className="h-full bg-indigo-600 transition-all duration-1000" 
                   style={{ width: `${(score / activeQuiz.questions.length) * 100}%` }}
                 />
               </div>
             </div>

             <button 
               onClick={() => startQuiz(activeQuiz)}
               className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium shadow-sm transition-all"
             >
               Try Again
             </button>
           </div>
         ) : (
           <div className="flex flex-col h-full">
              {/* Progress Bar */}
              <div className="h-2 bg-gray-100 w-full">
                <div 
                  className="h-full bg-indigo-600 transition-all duration-300"
                  style={{ width: `${((currentQuestionIndex) / activeQuiz.questions.length) * 100}%` }}
                />
              </div>

              <div className="flex-1 overflow-y-auto p-8 max-w-3xl mx-auto w-full">
                 <div className="flex justify-between items-center mb-8">
                   <span className="text-sm font-semibold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full">
                     Question {currentQuestionIndex + 1} of {activeQuiz.questions.length}
                   </span>
                   <span className="text-sm text-gray-500">Score: {score}</span>
                 </div>

                 <h2 className="text-2xl font-bold text-gray-900 mb-8 leading-snug">
                   {activeQuiz.questions[currentQuestionIndex].question}
                 </h2>

                 <div className="space-y-4">
                   {activeQuiz.questions[currentQuestionIndex].options.map((option, idx) => {
                     const isSelected = selectedAnswer === idx;
                     const isCorrect = idx === activeQuiz.questions[currentQuestionIndex].correctAnswerIndex;
                     const showCorrectness = selectedAnswer !== null;

                     let btnClass = "border-gray-200 hover:bg-gray-50 hover:border-gray-300";
                     if (showCorrectness) {
                       if (isCorrect) btnClass = "bg-green-50 border-green-500 text-green-700";
                       else if (isSelected && !isCorrect) btnClass = "bg-red-50 border-red-500 text-red-700";
                       else btnClass = "border-gray-200 opacity-50";
                     } else if (isSelected) {
                       btnClass = "border-indigo-500 bg-indigo-50 text-indigo-700";
                     }

                     return (
                       <button
                         key={idx}
                         onClick={() => handleAnswerSelect(idx)}
                         disabled={selectedAnswer !== null}
                         className={`w-full text-left p-4 rounded-xl border-2 transition-all flex items-center justify-between group ${btnClass}`}
                       >
                         <span className="font-medium text-lg">{option}</span>
                         {showCorrectness && isCorrect && <Check size={20} className="text-green-600" />}
                         {showCorrectness && isSelected && !isCorrect && <X size={20} className="text-red-600" />}
                       </button>
                     );
                   })}
                 </div>

                 {showExplanation && (
                   <div className="mt-8 p-6 bg-blue-50 rounded-xl border border-blue-100 animate-in fade-in slide-in-from-bottom-4">
                     <div className="flex items-start gap-3">
                       <HelpCircle className="text-blue-600 flex-shrink-0 mt-1" size={20} />
                       <div>
                         <h4 className="font-semibold text-blue-900 mb-1">Explanation</h4>
                         <p className="text-blue-800 leading-relaxed">
                           {activeQuiz.questions[currentQuestionIndex].explanation}
                         </p>
                       </div>
                     </div>
                   </div>
                 )}
              </div>

              <div className="p-6 border-t bg-gray-50 flex justify-end">
                <button
                  onClick={nextQuestion}
                  disabled={selectedAnswer === null}
                  className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium shadow-sm transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                >
                  {currentQuestionIndex === activeQuiz.questions.length - 1 ? 'Finish Quiz' : 'Next Question'}
                  <Play size={16} className="fill-current" />
                </button>
              </div>
           </div>
         )}
       </div>
    </div>
  );
};

export default QuizGenerator;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Auth from './components/Auth';
import DocumentUpload from './components/DocumentUpload';
import ChatInterface from './components/ChatInterface';
import NotesGenerator from './components/NotesGenerator';
import QuizGenerator from './components/QuizGenerator';
import { getCurrentUser, loginUser, logoutUser, saveDocument, getDocuments, getDocumentById } from './services/storage';
import { User, AppView, Document } from './types';
import { FileText, ArrowRight, Loader } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [isUploadOpen, setIsUploadOpen] = useState(false);
  const [activeDocumentId, setActiveDocumentId] = useState<string | null>(null);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const storedUser = getCurrentUser();
    if (storedUser) {
      setUser(storedUser);
    }
    refreshDocuments();
    setIsLoading(false);
  }, []);

  const refreshDocuments = () => {
    const docs = getDocuments();
    setDocuments(docs);
    // If we have an active doc that got deleted, reset; otherwise if no active doc and docs exist, set first.
    if (docs.length > 0 && !activeDocumentId) {
      setActiveDocumentId(docs[0].id);
    }
  };

  const handleLogin = async (email: string, name: string) => {
    const newUser = await loginUser(email, name);
    setUser(newUser);
  };

  const handleLogout = () => {
    logoutUser();
    setUser(null);
  };

  const handleUpload = async (file: File) => {
    const newDoc = await saveDocument(file);
    setDocuments(prev => [...prev, newDoc]);
    setActiveDocumentId(newDoc.id);
    setCurrentView(AppView.NOTES); // Go to notes after upload
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
         <Loader className="animate-spin text-indigo-600" size={32} />
      </div>
    );
  }

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const activeDocument = activeDocumentId ? getDocumentById(activeDocumentId) : null;

  return (
    <Layout
      user={user}
      currentView={currentView}
      onNavigate={setCurrentView}
      onLogout={handleLogout}
      onUploadClick={() => setIsUploadOpen(true)}
    >
      {/* View Routing */}
      {currentView === AppView.DASHBOARD && (
        <div>
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Welcome back, {user.name}</h1>
          <p className="text-gray-500 mb-8">Here are your study materials.</p>

          {documents.length === 0 ? (
            <div className="bg-white rounded-2xl p-12 text-center border border-dashed border-gray-300">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <FileText className="text-indigo-400" size={40} />
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">No documents yet</h3>
              <p className="text-gray-500 mb-6 max-w-md mx-auto">Upload your course syllabus, textbook chapters, or notes to get started with AI-powered studying.</p>
              <button
                onClick={() => setIsUploadOpen(true)}
                className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium shadow-sm transition-all"
              >
                Upload First PDF
              </button>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
              {documents.map(doc => (
                <div 
                  key={doc.id} 
                  className={`group bg-white rounded-2xl p-6 border transition-all cursor-pointer hover:shadow-md ${activeDocumentId === doc.id ? 'border-indigo-500 ring-1 ring-indigo-500' : 'border-gray-200 hover:border-indigo-300'}`}
                  onClick={() => setActiveDocumentId(doc.id)}
                >
                  <div className="flex items-start justify-between mb-4">
                    <div className="p-3 bg-indigo-50 text-indigo-600 rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                      <FileText size={24} />
                    </div>
                    {activeDocumentId === doc.id && (
                      <span className="text-xs font-semibold bg-indigo-100 text-indigo-700 px-2 py-1 rounded-full">Active</span>
                    )}
                  </div>
                  <h3 className="font-semibold text-gray-900 truncate mb-1">{doc.title}</h3>
                  <p className="text-sm text-gray-500 mb-4">Uploaded {new Date(doc.uploadDate).toLocaleDateString()}</p>

                  <div className="flex gap-2">
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.CHAT); }}
                      className="flex-1 text-center py-2 text-sm font-medium text-gray-600 bg-gray-50 rounded-lg hover:bg-gray-100 hover:text-indigo-600 transition-colors"
                    >
                      Chat
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.NOTES); }}
                      className="flex-1 text-center py-2 text-sm font-medium text-gray-600 bg-gray-50 rounded-lg hover:bg-gray-100 hover:text-indigo-600 transition-colors"
                    >
                      Notes
                    </button>
                  </div>
                </div>
              ))}

              <button 
                onClick={() => setIsUploadOpen(true)}
                className="bg-gray-50 rounded-2xl p-6 border-2 border-dashed border-gray-300 flex flex-col items-center justify-center text-gray-400 hover:border-indigo-400 hover:text-indigo-500 hover:bg-indigo-50/50 transition-all min-h-[200px]"
              >
                <div className="w-12 h-12 rounded-full border-2 border-current flex items-center justify-center mb-3 opacity-50">
                  <span className="text-2xl font-light">+</span>
                </div>
                <span className="font-medium">Upload New</span>
              </button>
            </div>
          )}
        </div>
      )}

      {currentView !== AppView.DASHBOARD && !activeDocument && (
        <div className="text-center py-20">
          <p className="text-gray-500">Please select a document from the Dashboard first.</p>
          <button 
            onClick={() => setCurrentView(AppView.DASHBOARD)}
            className="mt-4 text-indigo-600 hover:underline"
          >
            Go to Dashboard
          </button>
        </div>
      )}

      {activeDocument && (
        <>
          {currentView === AppView.CHAT && <ChatInterface document={activeDocument} />}
          {currentView === AppView.NOTES && <NotesGenerator document={activeDocument} />}
          {currentView === AppView.QUIZ && <QuizGenerator document={activeDocument} />}
        </>
      )}

      {isUploadOpen && (
        <DocumentUpload 
          onUpload={handleUpload} 
          onClose={() => setIsUploadOpen(false)} 
        />
      )}
    </Layout>
  );
};

export default App;

