    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      text: input.trim(),
      timestamp: Date.now()
    };

    // Optimistic update
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    saveChatMessage(document.id, userMsg);
    setInput('');
    setIsLoading(true);

    try {
      const apiHistory = messages.map(m => ({ role: m.role, text: m.text }));
      const responseText = await generateChatResponse(document, apiHistory, userMsg.text);

      const aiMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      saveChatMessage(document.id, aiMsg);

    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: "Oopsie! I had a little hiccup. Try again?",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white/60 backdrop-blur-md rounded-[2.5rem] border border-white/60 shadow-xl overflow-hidden">
      <div className="px-8 py-6 border-b border-white/50 bg-white/40 flex items-center justify-between">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-rose-100 rounded-full flex items-center justify-center text-rose-500 border-2 border-white shadow-sm">
             <Bot size={24} />
           </div>
           <div>
              <h3 className="font-bold text-gray-800 text-lg leading-tight">Lumi Chat</h3>
              <p className="text-xs font-bold text-gray-400 uppercase tracking-wide">Context: {document.title}</p>
           </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center text-gray-400 p-8">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-6 shadow-lg animate-float">
              <Sparkles size={40} className="text-yellow-400 fill-yellow-400" />
            </div>
            <p className="text-2xl font-black text-gray-700 mb-2">Hello friend!</p>
            <p className="font-medium text-gray-500 max-w-md leading-relaxed">
              I've read <strong>{document.title}</strong> and I'm ready to help. Ask me anything!
            </p>
          </div>
        ) : (
          messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              {msg.role === 'model' && (
                <div className="w-10 h-10 rounded-full bg-white border-2 border-rose-100 flex items-center justify-center flex-shrink-0 mt-2 shadow-sm">
                  <Bot size={20} className="text-rose-400" />
                </div>
              )}

              <div 
                className={`
                  max-w-[80%] rounded-3xl px-6 py-4 text-[15px] font-medium leading-relaxed shadow-sm
                  ${msg.role === 'user' 
                    ? 'bg-gray-800 text-white rounded-br-none' 
                    : 'bg-white border border-white/80 text-gray-700 rounded-bl-none'}
                `}
              >
                {msg.text}
              </div>

              {msg.role === 'user' && (
                <div className="w-10 h-10 rounded-full bg-blue-100 border-2 border-white flex items-center justify-center flex-shrink-0 mt-2 shadow-sm">
                  <UserIcon size={20} className="text-blue-500" />
                </div>
              )}
            </div>
          ))
        )}

        {isLoading && (
          <div className="flex gap-4 justify-start">
             <div className="w-10 h-10 rounded-full bg-white border-2 border-rose-100 flex items-center justify-center flex-shrink-0 mt-2 shadow-sm">
                <Bot size={20} className="text-rose-400" />
             </div>
             <div className="bg-white border border-white/50 rounded-3xl rounded-bl-none px-6 py-5 shadow-sm">
                <div className="flex gap-1.5">
                  <div className="w-2.5 h-2.5 bg-rose-300 rounded-full animate-bounce"></div>
                  <div className="w-2.5 h-2.5 bg-rose-300 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-2.5 h-2.5 bg-rose-300 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white/40 border-t border-white/50 backdrop-blur-md">
        <form onSubmit={handleSend} className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your question..."
            className="w-full pl-6 pr-14 py-5 bg-white border-2 border-transparent focus:border-rose-200 rounded-2xl shadow-sm focus:shadow-md outline-none transition-all font-bold text-gray-700 placeholder-gray-400"
          />
          <button 
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 top-2 bottom-2 aspect-square bg-gray-900 text-white rounded-xl hover:bg-gray-800 disabled:opacity-50 disabled:bg-gray-300 transition-all flex items-center justify-center hover:scale-95"
          >
            <Send size={20} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect } from 'react';
import { FileText, Sparkles, RefreshCw, Copy, Check, Highlighter } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Document, Note } from '../types';
import { generateStudyNotes } from '../services/gemini';
import { saveNote, getNotesByDocumentId } from '../services/storage';

interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const savedNotes = getNotesByDocumentId(document.id);
    setNotes(savedNotes);
    if (savedNotes.length > 0) {
      setActiveNote(savedNotes[0]);
    }
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const newNote = await generateStudyNotes(document);
      saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex gap-6">
      {/* Sidebar List */}
      <div className="w-72 flex-shrink-0 flex flex-col gap-4">
        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className="w-full flex items-center justify-center gap-3 bg-white hover:bg-gray-50 text-gray-800 py-4 px-6 rounded-2xl shadow-lg shadow-gray-100 border border-white/60 transition-all font-bold disabled:opacity-70 group"
        >
          {isGenerating ? (
            <RefreshCw className="animate-spin text-rose-500" size={20} />
          ) : (
            <Sparkles size={20} className="text-yellow-400 fill-yellow-400 group-hover:rotate-12 transition-transform" />
          )}
          {isGenerating ? 'Magic in progress...' : 'Create Magic Notes'}
        </button>

        <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
          {notes.length === 0 ? (
            <div className="text-center py-10 opacity-50">
                <FileText className="w-12 h-12 mx-auto mb-2" />
                <p className="font-bold text-sm">No notes found</p>
            </div>
          ) : (
            notes.map(note => (
              <button
                key={note.id}
                onClick={() => setActiveNote(note)}
                className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 group ${
                  activeNote?.id === note.id
                    ? 'bg-white border-rose-200 shadow-md shadow-rose-100 scale-[1.02]'
                    : 'bg-white/40 border-transparent hover:bg-white hover:shadow-sm'
                }`}
              >
                <div className="flex items-center gap-3 mb-1">
                  <div className={`p-2 rounded-lg ${activeNote?.id === note.id ? 'bg-rose-100 text-rose-500' : 'bg-gray-100 text-gray-400'}`}>
                      <FileText size={16} />
                  </div>
                  <span className="font-bold text-xs text-gray-400 uppercase tracking-wide">{new Date(note.createdAt).toLocaleDateString()}</span>
                </div>
                <p className={`font-bold text-sm truncate ${activeNote?.id === note.id ? 'text-gray-800' : 'text-gray-600'}`}>{note.title}</p>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main Content (Paper Look) */}
      <div className="flex-1 bg-[#fffdf0] rounded-[2rem] shadow-xl shadow-gray-200/50 flex flex-col overflow-hidden relative border border-[#f0e6d2]">
        {/* Paper Texture Decor */}
        <div className="absolute top-0 left-0 w-full h-8 bg-repeat-x opacity-20" style={{backgroundImage: 'linear-gradient(135deg, #000 5%, transparent 5%), linear-gradient(-135deg, #000 5%, transparent 5%)', backgroundSize: '10px 10px'}}></div>

        {activeNote ? (
          <>
            <div className="px-8 py-6 border-b border-[#e6dec8] flex items-center justify-between bg-[#fffef5]">
              <h2 className="font-hand text-3xl font-bold text-gray-800 truncate">{activeNote.title}</h2>
              <button 
                onClick={copyToClipboard}
                className="flex items-center gap-2 text-xs font-bold uppercase tracking-wider text-gray-500 hover:text-gray-900 transition-colors px-4 py-2 rounded-full hover:bg-[#f0e6d2]"
              >
                {copied ? <Check size={16} /> : <Copy size={16} />}
                {copied ? 'Copied!' : 'Copy'}
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-10 font-hand text-xl leading-loose text-gray-700">
              <ReactMarkdown 
                components={{
                   h1: ({node, ...props}) => <h1 className="font-sans text-4xl font-black text-gray-900 mb-6 pb-2 border-b-2 border-gray-900" {...props} />,
                   h2: ({node, ...props}) => <h2 className="font-sans text-2xl font-bold text-rose-500 mt-8 mb-4 flex items-center gap-2" {...props}><Highlighter size={20} className="text-yellow-300 fill-yellow-300" /> {props.children}</h2>,
                   h3: ({node, ...props}) => <h3 className="font-sans text-xl font-bold text-gray-800 mt-6 mb-3" {...props} />,
                   ul: ({node, ...props}) => <ul className="list-none pl-4 space-y-3 mb-6" {...props} />,
