import { GoogleGenAI, Type } from "@google/genai";
import { Document, Quiz, Note } from '../types';

// Helper to get fresh API client
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to prepare file part
const getFilePart = (doc: Document) => {
  // strip "data:application/pdf;base64," prefix if present
  const base64Data = doc.fileData.split(',')[1] || doc.fileData;
  return {
    inlineData: {
      mimeType: doc.mimeType,
      data: base64Data
    }
  };
};

export const generateChatResponse = async (
  doc: Document,
  history: { role: string; text: string }[],
  newMessage: string
): Promise<string> => {
  const ai = getAiClient();
  const filePart = getFilePart(doc);

  // We use flash for chat for lower latency
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are 'Lumi', a cute and intelligent study assistant.
    Your task is to answer questions based ONLY on the provided document.
    - Explain concepts clearly and simply.
    - Expand ideas instead of summarizing them.
    - Use examples where helpful.
    - NEVER hallucinate or use outside knowledge.
    - If the answer is not found in the document, respond exactly with: "I couldn’t find this in your notes."
  `;

  try {
    const contents = [
      { role: 'user', parts: [filePart, { text: "Analyze this document for our session." }] },
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: newMessage }] }
    ];

    const response = await ai.models.generateContent({
      model,
      contents: contents, // history + new message
      config: {
        systemInstruction,
        temperature: 0.4,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

export const generateStudyNotes = async (doc: Document): Promise<Note> => {
  const ai = getAiClient();
  const filePart = getFilePart(doc);
  const model = "gemini-3-pro-preview"; // Use Pro for higher quality reasoning/formatting

  const prompt = `
    Act as an elite academic tutor who creates "Aesthetic & Deep" study notes (Studygram style).
    Your goal is to extract the *most important* deep knowledge from this document and format it beautifully.

    STRICT GUIDELINES:
    1. **REMOVE FLUFF**: No introductions like "Here are your notes" or "In this document". Go straight to the core content.
    2. **DEEP DIVE**: Do not just summarize. Explain *mechanisms*, *relationships*, and *implications*.
    3. **SYMBOLS & AESTHETICS**:
       - Use "✨" or "📌" for major section headers.
       - Use "➜" (arrow) to show logic flow, cause-and-effect, or process steps.
       - Use "★" or "✦" for critical exam-ready points.
       - Use "💡" for "Insight" or "Tip".
       - Use "⚠️" for "Common Pitfalls".
    4. **FORMATTING**:
       - Use Markdown H1 (#) for the Main Title (Make it catchy).
       - Use Markdown H2 (##) for Sections.
       - Use **Bold** for keywords.
       - Use Blockquotes (>) for Definitions.

    REQUIRED STRUCTURE:
    # [Creative Title]

    ## ✨ Core Concepts & Fundamentals
    [Deep explanation of the main topic. Use paragraphs. Use ➜ to connect ideas.]

    ## 🧠 Deep Dive Analysis
    [Go into detail on the hardest parts of the text.]
    *   **Concept A**: Explanation...
        *   *Why it matters* ➜ Result.
    *   **Concept B**: Explanation...

    ## 📝 Vocabulary & Definitions
    > **[Term]**: [Precise definition]

    ## ⚡ Key Takeaways (Exam Cheat Sheet)
    *   ★ [Point 1]
    *   ★ [Point 2]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        temperature: 0.3, // Lower temp for more factual/structured output
      }
    });

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `✨ Notes: ${doc.title}`,
      content: response.text || "Failed to generate notes.",
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Notes Error:", error);
    throw error;
  }
};

export const generateQuiz = async (doc: Document, difficulty: 'easy' | 'medium' | 'hard'): Promise<Quiz> => {
  const ai = getAiClient();
  const filePart = getFilePart(doc);
  const model = "gemini-3-flash-preview";

  const prompt = `
    Generate a quiz with 5 multiple choice questions based on the document.
    Difficulty: ${difficulty}.
    Return the output in strictly valid JSON format matching this schema:
    {
      "questions": [
        {
          "question": "string",
          "options": ["string", "string", "string", "string"],
          "correctAnswerIndex": number (0-3),
          "explanation": "string"
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  correctAnswerIndex: { type: Type.INTEGER },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswerIndex", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonText = response.text || "{}";
    const parsed = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)} Quiz: ${doc.title}`,
      questions: parsed.questions?.map((q: any) => ({...q, id: crypto.randomUUID()})) || [],
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Quiz Error:", error);
    throw error;
  }
};

