// --- IndexedDB Helper ---
const DB_NAME = 'LumiDB';
const DB_VERSION = 1;

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;

      if (!db.objectStoreNames.contains('documents')) {
        db.createObjectStore('documents', { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains('notes')) {
        const store = db.createObjectStore('notes', { keyPath: 'id' });
        store.createIndex('documentId', 'documentId', { unique: false });
      }
      if (!db.objectStoreNames.contains('quizzes')) {
        const store = db.createObjectStore('quizzes', { keyPath: 'id' });
        store.createIndex('documentId', 'documentId', { unique: false });
      }
      if (!db.objectStoreNames.contains('chats')) {
        const store = db.createObjectStore('chats', { keyPath: 'id' });
        store.createIndex('documentId', 'documentId', { unique: false });
        store.createIndex('timestamp', 'timestamp', { unique: false });
      }
    };
  });
};

const dbOp = async <T>(
  storeName: string, 
  mode: 'readonly' | 'readwrite', 
  callback: (store: IDBObjectStore) => IDBRequest | void
): Promise<T> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(storeName, mode);
    const store = transaction.objectStore(storeName);
    const request = callback(store);

    if (request) {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    } else {
      transaction.oncomplete = () => resolve(undefined as unknown as T);
      transaction.onerror = () => reject(transaction.error);
    }
  });
};

const getAllFromIndex = async <T>(storeName: string, indexName: string, value: string): Promise<T[]> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(storeName, 'readonly');
    const store = transaction.objectStore(storeName);
    const index = store.index(indexName);
    const request = index.getAll(value);
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

const getAll = async <T>(storeName: string): Promise<T[]> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(storeName, 'readonly');
    const store = transaction.objectStore(storeName);
    const request = store.getAll();
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

// --- Documents ---
export const saveDocument = async (file: File): Promise<Document> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64String = reader.result as string;
        const newDoc: Document = {
          id: crypto.randomUUID(),
          title: file.name,
          uploadDate: new Date().toISOString(),
          fileData: base64String,
          mimeType: file.type,
          size: file.size
        };

        await dbOp('documents', 'readwrite', (store) => store.add(newDoc));
        resolve(newDoc);
      } catch (e) {
        reject(e);
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const getDocuments = async (): Promise<Document[]> => {
  return getAll<Document>('documents');
};

export const getDocumentById = async (id: string): Promise<Document | undefined> => {
  return dbOp<Document>('documents', 'readonly', (store) => store.get(id));
};

export const deleteDocument = async (id: string): Promise<void> => {
  await dbOp('documents', 'readwrite', (store) => store.delete(id));
};

// --- Notes ---
export const saveNote = async (note: Note): Promise<void> => {
  await dbOp('notes', 'readwrite', (store) => store.put(note));
};

export const getNotes = async (): Promise<Note[]> => {
  return getAll<Note>('notes');
};

export const getNotesByDocumentId = async (docId: string): Promise<Note[]> => {
  return getAllFromIndex<Note>('notes', 'documentId', docId);
};

// --- Quizzes ---
export const saveQuiz = async (quiz: Quiz): Promise<void> => {
  await dbOp('quizzes', 'readwrite', (store) => store.add(quiz));
};

export const getQuizzes = async (): Promise<Quiz[]> => {
  return getAll<Quiz>('quizzes');
};

export const getQuizzesByDocumentId = async (docId: string): Promise<Quiz[]> => {
  return getAllFromIndex<Quiz>('quizzes', 'documentId', docId);
};

// --- Chats ---
export const saveChatMessage = async (docId: string, message: ChatMessage): Promise<void> => {
  // We store messages flat but indexed by documentId
  // We add a 'documentId' field to the stored object which isn't in the ChatMessage type strictly, 
  // but we can cast or extend. For simplicity, let's assume we store the object as is plus the index key.
  // Actually, Typescript might complain. Let's create a storage type or just assume flexible storage.
  const msgToStore = { ...message, documentId: docId };
  await dbOp('chats', 'readwrite', (store) => store.add(msgToStore));
};

export const getChatHistory = async (docId: string): Promise<ChatMessage[]> => {
  const msgs = await getAllFromIndex<ChatMessage & { timestamp: number }>('chats', 'documentId', docId);
  return msgs.sort((a, b) => a.timestamp - b.timestamp);
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Auth from './components/Auth';
import LandingPage from './components/LandingPage';
import DocumentUpload from './components/DocumentUpload';
import ChatInterface from './components/ChatInterface';
import NotesGenerator from './components/NotesGenerator';
import QuizGenerator from './components/QuizGenerator';
import { getCurrentUser, loginUser, logoutUser, saveDocument, getDocuments, getDocumentById } from './services/storage';
import { User, AppView, Document } from './types';
import { Cloud, ArrowRight, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showLanding, setShowLanding] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [isUploadOpen, setIsUploadOpen] = useState(false);
  const [activeDocumentId, setActiveDocumentId] = useState<string | null>(null);
  const [activeDocument, setActiveDocument] = useState<Document | null>(null);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const init = async () => {
      const storedUser = getCurrentUser();
      if (storedUser) {
        setUser(storedUser);
        setShowLanding(false);
      }
      await refreshDocuments();
      setIsLoading(false);
    };
    init();
  }, []);

  // Update active document object when ID changes
  useEffect(() => {
    const fetchDoc = async () => {
      if (activeDocumentId) {
        const doc = await getDocumentById(activeDocumentId);
        setActiveDocument(doc || null);
      } else {
        setActiveDocument(null);
      }
    };
    fetchDoc();
  }, [activeDocumentId]);

  const refreshDocuments = async () => {
    const docs = await getDocuments();
    setDocuments(docs);
    if (docs.length > 0 && !activeDocumentId) {
      setActiveDocumentId(docs[0].id);
    }
  };

  const handleLogin = async (email: string, name: string) => {
    const newUser = await loginUser(email, name);
    setUser(newUser);
    setShowLanding(false);
  };

  const handleLogout = () => {
    logoutUser();
    setUser(null);
    setShowLanding(true);
  };

  const handleUpload = async (file: File) => {
    try {
      const newDoc = await saveDocument(file);
      setDocuments(prev => [...prev, newDoc]);
      setActiveDocumentId(newDoc.id);
      setCurrentView(AppView.NOTES);
    } catch (e) {
      console.error("Upload failed", e);
      alert("Failed to save document. It might be too large.");
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#fff0f3]">
         <div className="relative">
            <div className="w-16 h-16 border-4 border-rose-200 border-t-rose-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center">
               <Sparkles size={20} className="text-rose-500 animate-pulse" />
            </div>
         </div>
      </div>
    );
  }

  // Render Logic
  if (showLanding && !user) {
    return <LandingPage onGetStarted={() => setShowLanding(false)} />;
  }

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <Layout
      user={user}
      currentView={currentView}
      onNavigate={setCurrentView}
      onLogout={handleLogout}
      onUploadClick={() => setIsUploadOpen(true)}
    >
      {/* View Routing */}
      {currentView === AppView.DASHBOARD && (
        <div className="p-4 lg:p-10">
          <div className="mb-10">
             <div className="inline-block bg-white/50 backdrop-blur-sm px-4 py-2 rounded-full border border-white/60 mb-4 animate-float">
                <span className="text-sm font-bold text-gray-500">✨ Ready to learn?</span>
             </div>
             <h1 className="text-4xl lg:text-5xl font-black text-gray-800 mb-3">Hi, {user.name}</h1>
             <p className="text-gray-500 font-medium text-lg">Pick a document to start your session.</p>
          </div>

          {documents.length === 0 ? (
            <div className="bg-white/60 backdrop-blur-md rounded-[3rem] p-16 text-center border-2 border-dashed border-gray-300/60 hover:border-rose-300 transition-colors group">
              <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform duration-300">
                <Cloud className="text-rose-400" size={48} strokeWidth={2.5} />
              </div>
              <h3 className="text-2xl font-black text-gray-800 mb-3">Your library is empty</h3>
              <p className="text-gray-500 mb-8 max-w-md mx-auto font-medium">Upload your first PDF and watch Lumi turn it into magic study material.</p>
              <button
                onClick={() => setIsUploadOpen(true)}
                className="px-8 py-4 bg-gray-900 hover:bg-gray-800 text-white rounded-2xl font-bold shadow-xl shadow-rose-100 transition-all hover:-translate-y-1"
              >
                Upload First PDF
              </button>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
              {documents.map(doc => (
                <div 
                  key={doc.id} 
                  className={`group relative bg-white/70 backdrop-blur-md rounded-[2.5rem] p-8 border transition-all cursor-pointer hover:shadow-xl hover:-translate-y-2 duration-300 ${activeDocumentId === doc.id ? 'border-rose-400 ring-4 ring-rose-100 shadow-lg shadow-rose-100' : 'border-white/50 hover:border-rose-200'}`}
                  onClick={() => setActiveDocumentId(doc.id)}
                >
                  <div className="flex items-start justify-between mb-6">
                    <div className="w-14 h-14 bg-gradient-to-br from-rose-100 to-orange-100 text-rose-500 rounded-2xl flex items-center justify-center group-hover:rotate-6 transition-transform shadow-inner">
                      <Cloud size={28} strokeWidth={2.5} />
                    </div>
                    {activeDocumentId === doc.id && (
                      <span className="text-[10px] font-black uppercase tracking-widest bg-rose-500 text-white px-3 py-1 rounded-full shadow-md">Active</span>
                    )}
                  </div>
                  <h3 className="text-xl font-bold text-gray-800 truncate mb-2">{doc.title}</h3>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-wide mb-8">Added {new Date(doc.uploadDate).toLocaleDateString()}</p>

                  <div className="flex gap-3">
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.CHAT); }}
                      className="flex-1 py-3 text-sm font-bold text-gray-600 bg-white border border-gray-100 rounded-xl hover:bg-gray-50 hover:text-gray-900 transition-colors shadow-sm"
                    >
                      Chat
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.NOTES); }}
                      className="flex-1 py-3 text-sm font-bold text-gray-600 bg-white border border-gray-100 rounded-xl hover:bg-gray-50 hover:text-gray-900 transition-colors shadow-sm"
                    >
                      Notes
                    </button>
                  </div>
                </div>
              ))}

              <button 
                onClick={() => setIsUploadOpen(true)}
                className="bg-white/40 backdrop-blur-sm rounded-[2.5rem] p-6 border-2 border-dashed border-gray-300 hover:border-rose-400 hover:bg-rose-50/50 transition-all flex flex-col items-center justify-center text-gray-400 hover:text-rose-500 min-h-[240px] group"
              >
                <div className="w-16 h-16 rounded-full bg-white border-2 border-current flex items-center justify-center mb-4 group-hover:scale-110 transition-transform shadow-sm">
                  <span className="text-3xl font-light pb-1">+</span>
                </div>
                <span className="font-bold text-lg">Add New</span>
              </button>
            </div>
          )}
        </div>
      )}

      {currentView !== AppView.DASHBOARD && !activeDocument && (
        <div className="flex flex-col items-center justify-center h-full text-center p-8">
          <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mb-6 animate-pulse">
            <Cloud size={40} className="text-gray-400" />
          </div>
          <h2 className="text-2xl font-black text-gray-800 mb-2">Nothing selected</h2>
          <p className="text-gray-500 font-medium mb-6">Select a document from the library to start.</p>
          <button 
            onClick={() => setCurrentView(AppView.DASHBOARD)}
            className="flex items-center gap-2 px-6 py-3 bg-gray-900 text-white rounded-xl font-bold hover:bg-gray-800 transition-colors"
          >
            Go to Library <ArrowRight size={16} />
          </button>
        </div>
      )}

      {activeDocument && (
        <div className="h-full">
          {currentView === AppView.CHAT && <ChatInterface document={activeDocument} />}
          {currentView === AppView.NOTES && <NotesGenerator document={activeDocument} />}
          {currentView === AppView.QUIZ && <QuizGenerator document={activeDocument} />}
        </div>
      )}

      {isUploadOpen && (
        <DocumentUpload 
          onUpload={handleUpload} 
          onClose={() => setIsUploadOpen(false)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Send, Bot, User as UserIcon, Sparkles } from 'lucide-react';
import { Document, ChatMessage } from '../types';
import { generateChatResponse } from '../services/gemini';
import { saveChatMessage, getChatHistory } from '../services/storage';

interface ChatInterfaceProps {
  document: Document;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ document }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Load history
    const load = async () => {
      const history = await getChatHistory(document.id);
      setMessages(history);
    };
    load();
  }, [document.id]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      text: input.trim(),
      timestamp: Date.now()
    };

    // Optimistic update
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    // Note: We don't await save here to keep UI snappy, but we catch errors if needed
    saveChatMessage(document.id, userMsg).catch(console.error);

    setInput('');
    setIsLoading(true);

    try {
      const apiHistory = messages.map(m => ({ role: m.role, text: m.text }));
      const responseText = await generateChatResponse(document, apiHistory, userMsg.text);

      const aiMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      await saveChatMessage(document.id, aiMsg);

    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: "Oopsie! I had a little hiccup. Try again?",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white/60 backdrop-blur-md rounded-[2.5rem] border border-white/60 shadow-xl overflow-hidden">
      <div className="px-8 py-6 border-b border-white/50 bg-white/40 flex items-center justify-between">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-rose-100 rounded-full flex items-center justify-center text-rose-500 border-2 border-white shadow-sm">
             <Bot size={24} />
           </div>
           <div>
              <h3 className="font-bold text-gray-800 text-lg leading-tight">Lumi Chat</h3>
              <p className="text-xs font-bold text-gray-400 uppercase tracking-wide">Context: {document.title}</p>
           </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center text-gray-400 p-8">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-6 shadow-lg animate-float">
              <Sparkles size={40} className="text-yellow-400 fill-yellow-400" />
            </div>
            <p className="text-2xl font-black text-gray-700 mb-2">Hello friend!</p>
            <p className="font-medium text-gray-500 max-w-md leading-relaxed">
              I've read <strong>{document.title}</strong> and I'm ready to help. Ask me anything!
            </p>
          </div>
        ) : (
          messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              {msg.role === 'model' && (
                <div className="w-10 h-10 rounded-full bg-white border-2 border-rose-100 flex items-center justify-center flex-shrink-0 mt-2 shadow-sm">
                  <Bot size={20} className="text-rose-400" />
                </div>
              )}

              <div 
                className={`
                  max-w-[80%] rounded-3xl px-6 py-4 text-[15px] font-medium leading-relaxed shadow-sm
                  ${msg.role === 'user' 
                    ? 'bg-gray-800 text-white rounded-br-none' 
                    : 'bg-white border border-white/80 text-gray-700 rounded-bl-none'}
                `}
              >
                {msg.text}
              </div>

              {msg.role === 'user' && (
                <div className="w-10 h-10 rounded-full bg-blue-100 border-2 border-white flex items-center justify-center flex-shrink-0 mt-2 shadow-sm">
                  <UserIcon size={20} className="text-blue-500" />
                </div>
              )}
            </div>
          ))
        )}

        {isLoading && (
          <div className="flex gap-4 justify-start">
             <div className="w-10 h-10 rounded-full bg-white border-2 border-rose-100 flex items-center justify-center flex-shrink-0 mt-2 shadow-sm">
                <Bot size={20} className="text-rose-400" />
             </div>
             <div className="bg-white border border-white/50 rounded-3xl rounded-bl-none px-6 py-5 shadow-sm">
                <div className="flex gap-1.5">
                  <div className="w-2.5 h-2.5 bg-rose-300 rounded-full animate-bounce"></div>
                  <div className="w-2.5 h-2.5 bg-rose-300 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-2.5 h-2.5 bg-rose-300 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white/40 border-t border-white/50 backdrop-blur-md">
        <form onSubmit={handleSend} className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your question..."
            className="w-full pl-6 pr-14 py-5 bg-white border-2 border-transparent focus:border-rose-200 rounded-2xl shadow-sm focus:shadow-md outline-none transition-all font-bold text-gray-700 placeholder-gray-400"
          />
          <button 
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 top-2 bottom-2 aspect-square bg-gray-900 text-white rounded-xl hover:bg-gray-800 disabled:opacity-50 disabled:bg-gray-300 transition-all flex items-center justify-center hover:scale-95"
          >
            <Send size={20} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect } from 'react';
import { FileText, Sparkles, RefreshCw, Copy, Check, Highlighter, Star } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Document, Note } from '../types';
import { generateStudyNotes } from '../services/gemini';
import { saveNote, getNotesByDocumentId } from '../services/storage';

interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const load = async () => {
      const savedNotes = await getNotesByDocumentId(document.id);
      setNotes(savedNotes);
      if (savedNotes.length > 0) {
        setActiveNote(savedNotes[0]);
      } else {
        setActiveNote(null);
      }
    };
    load();
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const newNote = await generateStudyNotes(document);
      await saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
