                  <span className="font-bold text-xs text-gray-400 uppercase tracking-wide">{new Date(note.createdAt).toLocaleDateString()}</span>
                </div>
                <p className={`font-bold text-sm truncate ${activeNote?.id === note.id ? 'text-gray-800' : 'text-gray-600'}`}>{note.title}</p>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main Content (Paper Look) */}
      <div className="flex-1 bg-[#fffdf0] rounded-[2rem] shadow-xl shadow-gray-200/50 flex flex-col overflow-hidden relative border border-[#f0e6d2]">
        {/* Paper Texture Decor */}
        <div className="absolute top-0 left-0 w-full h-8 bg-repeat-x opacity-20" style={{backgroundImage: 'linear-gradient(135deg, #000 5%, transparent 5%), linear-gradient(-135deg, #000 5%, transparent 5%)', backgroundSize: '10px 10px'}}></div>

        {activeNote ? (
          <>
            <div className="px-8 py-6 border-b border-[#e6dec8] flex items-center justify-between bg-[#fffef5]">
