              >
                {copied ? <Check size={16} /> : <Copy size={16} />}
                {copied ? 'Copied!' : 'Copy'}
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-12 font-hand text-xl leading-loose text-gray-800">
              <ReactMarkdown 
                components={{
