interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const load = async () => {
      const savedNotes = await getNotesByDocumentId(document.id);
      setNotes(savedNotes);
      if (savedNotes.length > 0) {
        setActiveNote(savedNotes[0]);
      } else {
        setActiveNote(null);
      }
    };
    load();
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const newNote = await generateStudyNotes(document);
      await saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex gap-6">
      {/* Sidebar List */}
      <div className="w-72 flex-shrink-0 flex flex-col gap-4">
        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className="w-full flex items-center justify-center gap-3 bg-white hover:bg-gray-50 text-gray-800 py-4 px-6 rounded-2xl shadow-lg shadow-gray-100 border border-white/60 transition-all font-bold disabled:opacity-70 group"
        >
          {isGenerating ? (
            <RefreshCw className="animate-spin text-rose-500" size={20} />
          ) : (
            <Sparkles size={20} className="text-yellow-400 fill-yellow-400 group-hover:rotate-12 transition-transform" />
          )}
          {isGenerating ? 'Magic in progress...' : 'Create Magic Notes'}
        </button>

        <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
          {notes.length === 0 ? (
            <div className="text-center py-10 opacity-50">
                <FileText className="w-12 h-12 mx-auto mb-2" />
                <p className="font-bold text-sm">No notes found</p>
            </div>
          ) : (
            notes.map(note => (
              <button
                key={note.id}
                onClick={() => setActiveNote(note)}
                className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 group ${
                  activeNote?.id === note.id
