  const [activeDocumentId, setActiveDocumentId] = useState<string | null>(null);
  const [activeDocument, setActiveDocument] = useState<Document | null>(null);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const init = async () => {
      const storedUser = getCurrentUser();
      if (storedUser) {
        setUser(storedUser);
        setShowLanding(false);
      }
      await refreshDocuments();
      setIsLoading(false);
    };
    init();
  }, []);

  // Update active document object when ID changes
  useEffect(() => {
    const fetchDoc = async () => {
      if (activeDocumentId) {
        const doc = await getDocumentById(activeDocumentId);
        setActiveDocument(doc || null);
      } else {
        setActiveDocument(null);
      }
    };
    fetchDoc();
  }, [activeDocumentId]);

  const refreshDocuments = async () => {
    const docs = await getDocuments();
    setDocuments(docs);
    if (docs.length > 0 && !activeDocumentId) {
      setActiveDocumentId(docs[0].id);
    }
  };

  const handleLogin = async (email: string, name: string) => {
    const newUser = await loginUser(email, name);
    setUser(newUser);
    setShowLanding(false);
  };

  const handleLogout = () => {
    logoutUser();
    setUser(null);
    setShowLanding(true);
  };

  const handleUpload = async (file: File) => {
    try {
      const newDoc = await saveDocument(file);
      setDocuments(prev => [...prev, newDoc]);
      setActiveDocumentId(newDoc.id);
      setCurrentView(AppView.NOTES);
    } catch (e) {
      console.error("Upload failed", e);
      alert("Failed to save document. It might be too large.");
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#fff0f3]">
         <div className="relative animate-pop-in">
            <div className="w-16 h-16 border-4 border-rose-200 border-t-rose-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center">
               <Sparkles size={20} className="text-rose-500 animate-pulse" />
            </div>
         </div>
      </div>
    );
  }

  // Render Logic
  if (showLanding && !user) {
    return <LandingPage onGetStarted={() => setShowLanding(false)} />;
  }

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <Layout
      user={user}
      currentView={currentView}
      onNavigate={setCurrentView}
      onLogout={handleLogout}
      onUploadClick={() => setIsUploadOpen(true)}
    >
      {/* View Routing with Animations */}
      {currentView === AppView.DASHBOARD && (
        <div key="dashboard" className="p-4 lg:p-10 animate-slide-up">
          <div className="mb-10">
             <div className="inline-block bg-white/50 backdrop-blur-sm px-4 py-2 rounded-full border border-white/60 mb-4 animate-float">
                <span className="text-sm font-bold text-gray-500">✨ Ready to learn?</span>
             </div>
             <h1 className="text-4xl lg:text-5xl font-black text-gray-800 mb-3 animate-fade-in stagger-1 opacity-0">Hi, {user.name}</h1>
             <p className="text-gray-500 font-medium text-lg animate-fade-in stagger-2 opacity-0">Pick a document to start your session.</p>
          </div>

          {documents.length === 0 ? (
            <div className="bg-white/60 backdrop-blur-md rounded-[3rem] p-16 text-center border-2 border-dashed border-gray-300/60 hover:border-rose-300 transition-all duration-300 group animate-scale-in">
              <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform duration-300">
                <Cloud className="text-rose-400" size={48} strokeWidth={2.5} />
              </div>
              <h3 className="text-2xl font-black text-gray-800 mb-3">Your library is empty</h3>
              <p className="text-gray-500 mb-8 max-w-md mx-auto font-medium">Upload your first PDF and watch Lumi turn it into magic study material.</p>
              <button
                onClick={() => setIsUploadOpen(true)}
                className="px-8 py-4 bg-gray-900 hover:bg-gray-800 text-white rounded-2xl font-bold shadow-xl shadow-rose-100 transition-all hover:-translate-y-1 active:scale-95"
              >
                Upload First PDF
              </button>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in stagger-3 opacity-0">
              {documents.map((doc, idx) => (
                <div 
                  key={doc.id} 
                  style={{ animationDelay: `${idx * 100}ms` }}
                  className={`group relative bg-white/70 backdrop-blur-md rounded-[2.5rem] p-8 border transition-all cursor-pointer hover:shadow-xl hover:-translate-y-2 duration-300 animate-slide-up ${activeDocumentId === doc.id ? 'border-rose-400 ring-4 ring-rose-100 shadow-lg shadow-rose-100' : 'border-white/50 hover:border-rose-200'}`}
                  onClick={() => setActiveDocumentId(doc.id)}
                >
                  <div className="flex items-start justify-between mb-6">
                    <div className="w-14 h-14 bg-gradient-to-br from-rose-100 to-orange-100 text-rose-500 rounded-2xl flex items-center justify-center group-hover:rotate-6 transition-transform shadow-inner">
                      <Cloud size={28} strokeWidth={2.5} />
                    </div>
                    {activeDocumentId === doc.id && (
                      <span className="text-[10px] font-black uppercase tracking-widest bg-rose-500 text-white px-3 py-1 rounded-full shadow-md animate-pop-in">Active</span>
                    )}
                  </div>
                  <h3 className="text-xl font-bold text-gray-800 truncate mb-2">{doc.title}</h3>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-wide mb-8">Added {new Date(doc.uploadDate).toLocaleDateString()}</p>

                  <div className="flex gap-3">
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.CHAT); }}
                      className="flex-1 py-3 text-sm font-bold text-gray-600 bg-white border border-gray-100 rounded-xl hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm hover:shadow-md active:scale-95"
                    >
                      Chat
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.NOTES); }}
                      className="flex-1 py-3 text-sm font-bold text-gray-600 bg-white border border-gray-100 rounded-xl hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm hover:shadow-md active:scale-95"
                    >
                      Notes
                    </button>
                  </div>
                </div>
              ))}

              <button 
                onClick={() => setIsUploadOpen(true)}
                className="bg-white/40 backdrop-blur-sm rounded-[2.5rem] p-6 border-2 border-dashed border-gray-300 hover:border-rose-400 hover:bg-rose-50/50 transition-all flex flex-col items-center justify-center text-gray-400 hover:text-rose-500 min-h-[240px] group animate-slide-up"
                style={{ animationDelay: `${documents.length * 100}ms` }}
              >
                <div className="w-16 h-16 rounded-full bg-white border-2 border-current flex items-center justify-center mb-4 group-hover:scale-110 transition-transform shadow-sm">
                  <span className="text-3xl font-light pb-1">+</span>
                </div>
                <span className="font-bold text-lg">Add New</span>
              </button>
            </div>
          )}
        </div>
      )}

      {currentView !== AppView.DASHBOARD && !activeDocument && (
        <div key="empty" className="flex flex-col items-center justify-center h-full text-center p-8 animate-fade-in">
          <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mb-6 animate-pulse">
            <Cloud size={40} className="text-gray-400" />
          </div>
          <h2 className="text-2xl font-black text-gray-800 mb-2">Nothing selected</h2>
          <p className="text-gray-500 font-medium mb-6">Select a document from the library to start.</p>
          <button 
            onClick={() => setCurrentView(AppView.DASHBOARD)}
            className="flex items-center gap-2 px-6 py-3 bg-gray-900 text-white rounded-xl font-bold hover:bg-gray-800 transition-all hover:scale-105 active:scale-95"
          >
            Go to Library <ArrowRight size={16} />
          </button>
        </div>
      )}

      {activeDocument && (
        <div key={currentView} className="h-full animate-slide-up">
          {currentView === AppView.CHAT && <ChatInterface document={activeDocument} />}
          {currentView === AppView.NOTES && <NotesGenerator document={activeDocument} />}
          {currentView === AppView.QUIZ && <QuizGenerator document={activeDocument} />}
        </div>
      )}

      {isUploadOpen && (
        <DocumentUpload 
          onUpload={handleUpload} 
          onClose={() => setIsUploadOpen(false)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Send, Bot, User as UserIcon, Sparkles } from 'lucide-react';
import { Document, ChatMessage } from '../types';
import { generateChatResponse } from '../services/gemini';
import { saveChatMessage, getChatHistory } from '../services/storage';

interface ChatInterfaceProps {
  document: Document;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ document }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Load history
    const load = async () => {
      const history = await getChatHistory(document.id);
      setMessages(history);
    };
    load();
  }, [document.id]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      text: input.trim(),
      timestamp: Date.now()
    };

    // Optimistic update
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    // Note: We don't await save here to keep UI snappy, but we catch errors if needed
    saveChatMessage(document.id, userMsg).catch(console.error);

    setInput('');
    setIsLoading(true);

    try {
      const apiHistory = messages.map(m => ({ role: m.role, text: m.text }));
      const responseText = await generateChatResponse(document, apiHistory, userMsg.text);

      const botMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, botMsg]);
      await saveChatMessage(document.id, botMsg);
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: "I'm having a little trouble thinking right now. Try again?",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full relative">
      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-4 lg:p-8 space-y-6 custom-scrollbar">
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center opacity-60 animate-fade-in">
            <div className="w-20 h-20 bg-white rounded-3xl rotate-6 flex items-center justify-center mb-6 shadow-lg animate-float">
              <Sparkles size={40} className="text-rose-400" />
            </div>
            <p className="font-bold text-gray-500 text-lg">Ask me anything about <br/> <span className="text-rose-500">"{document.title}"</span></p>
          </div>
        ) : (
          messages.map((msg, idx) => (
            <div
              key={msg.id}
              className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'} animate-slide-up`}
              style={{ animationDelay: `${idx * 50}ms` }}
            >
              <div className={`
                w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 shadow-sm
                ${msg.role === 'user' ? 'bg-gray-900 text-white' : 'bg-white text-rose-500 border border-rose-100'}
              `}>
                {msg.role === 'user' ? <UserIcon size={20} /> : <Sparkles size={20} />}
              </div>

              <div className={`
                max-w-[80%] p-5 rounded-2xl text-base leading-relaxed shadow-sm relative group transition-all duration-300 hover:shadow-md
                ${msg.role === 'user' 
                  ? 'bg-gray-900 text-white rounded-tr-none' 
                  : 'bg-white text-gray-800 border border-white/60 rounded-tl-none'}
              `}>
                {msg.text}
              </div>
            </div>
          ))
        )}

        {isLoading && (
          <div className="flex gap-4 animate-slide-up">
            <div className="w-10 h-10 rounded-xl bg-white text-rose-500 border border-rose-100 flex items-center justify-center flex-shrink-0 shadow-sm">
               <Sparkles size={20} className="animate-spin" />
            </div>
            <div className="bg-white/80 p-5 rounded-2xl rounded-tl-none border border-white/50 shadow-sm flex items-center gap-2">
              <div className="w-2 h-2 bg-rose-400 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-rose-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-2 h-2 bg-rose-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 lg:p-6 bg-white/60 backdrop-blur-md border-t border-white/50">
        <form 
          onSubmit={handleSend}
          className="relative max-w-4xl mx-auto flex items-center gap-2 bg-white p-2 rounded-3xl shadow-xl shadow-rose-100/50 border border-rose-50 transition-all focus-within:ring-4 focus-within:ring-rose-100 focus-within:border-rose-300"
        >
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask a question..."
            className="flex-1 bg-transparent px-6 py-3 outline-none text-gray-700 font-bold placeholder:text-gray-400 placeholder:font-medium"
          />
          <button 
            type="submit"
            disabled={!input.trim() || isLoading}
            className="p-4 bg-gray-900 text-white rounded-2xl hover:bg-rose-500 disabled:opacity-50 disabled:hover:bg-gray-900 transition-all duration-300 shadow-md hover:scale-105 active:scale-95"
          >
            <Send size={20} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect } from 'react';
import { FileText, Sparkles, RefreshCw, Copy, Check, Highlighter, Star } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Document, Note } from '../types';
import { generateStudyNotes } from '../services/gemini';
import { saveNote, getNotesByDocumentId } from '../services/storage';

interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const load = async () => {
      const savedNotes = await getNotesByDocumentId(document.id);
      setNotes(savedNotes);
      if (savedNotes.length > 0) {
        setActiveNote(savedNotes[0]);
      } else {
        setActiveNote(null);
      }
    };
    load();
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const newNote = await generateStudyNotes(document);
      await saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex gap-6">
      {/* Sidebar List */}
      <div className="w-72 flex-shrink-0 flex flex-col gap-4 animate-slide-up">
