              >
                {copied ? <Check size={16} className="text-green-500" /> : <Copy size={16} />}
                {copied ? 'Copied!' : 'Copy'}
              </button>
            </div>
            <div key={activeNote.id} className="flex-1 overflow-y-auto p-12 font-hand text-xl leading-loose text-gray-800 animate-fade-in">
              <ReactMarkdown 
