                     let btnClass = "bg-white border-2 border-gray-100 hover:border-blue-300 hover:bg-blue-50/30 hover:scale-[1.01]";
                     let icon = <div className="w-6 h-6 rounded-full border-2 border-gray-200 flex-shrink-0" />;

                     if (showCorrectness) {
