import { GoogleGenAI, Type } from "@google/genai";
import { Document, Quiz, Note } from '../types';

// Helper to get fresh API client
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert Blob/File to Base64
const fileToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g. "data:image/png;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

// Helper to prepare file part
const getFilePart = async (doc: Document) => {
  const base64Data = await fileToBase64(doc.file);
  return {
    inlineData: {
      mimeType: doc.mimeType,
      data: base64Data
    }
  };
};

export const generateChatResponse = async (
  doc: Document,
  history: { role: string; text: string }[],
  newMessage: string
): Promise<string> => {
  const ai = getAiClient();
  try {
    const filePart = await getFilePart(doc);

    // We use flash for chat for lower latency
    const model = "gemini-3-flash-preview";

    const systemInstruction = `
      You are 'Lumi', a cute and intelligent study assistant.
      Your task is to answer questions based ONLY on the provided document.
      - Explain concepts clearly and simply.
      - Expand ideas instead of summarizing them.
      - Use examples where helpful.
      - NEVER hallucinate or use outside knowledge.
      - If the answer is not found in the document, respond exactly with: "I couldn’t find this in your notes."
    `;

    const contents = [
      { role: 'user', parts: [filePart, { text: "Analyze this document for our session." }] },
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: newMessage }] }
    ];

    const response = await ai.models.generateContent({
      model,
      contents: contents, 
      config: {
        systemInstruction,
        temperature: 0.4,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

export const generateStudyNotes = async (doc: Document): Promise<Note> => {
  const ai = getAiClient();
  try {
    const filePart = await getFilePart(doc);
    const model = "gemini-3-pro-preview"; 

    // Updated prompt for deeper, non-summary content
    const prompt = `
      Act as an elite academic tutor who creates "Aesthetic & Deep" study notes.
      Your goal is to extract the knowledge from this document and format it into a comprehensive study guide.

      CRITICAL INSTRUCTION: **DO NOT SUMMARIZE.** 
      - You must EXPAND on concepts. 
      - If a concept is mentioned, explain it fully including background, context, how it works, and why it matters.
      - Write as if you are writing a high-quality textbook, not a cheat sheet.
      - Use multiple paragraphs for complex ideas.

      AESTHETIC SYMBOLS (Use these specifically):
      - Headers: ꩜, ❀, ✎, ⚡, ❖
      - Bullets: ◦, ▪, ▫
      - Arrows: ↝, ⇢, ⟿
      - Important: ⋆, ✦, ✳
      - Definitions: ❞

      REQUIRED STRUCTURE:
      # ❀ [Creative Title related to the topic]

      ## ꩜ Core Concepts
      [Provide a detailed explanation of the core themes. Connect ideas logically using arrows ↝.]

      ## ⚡ Deep Dive Analysis
      [Identify the most complex or important topics and break them down EXTENSIVELY.]
      *   **[Concept Name]**: [Detailed explanation, at least 3-4 sentences.]
          *   *Mechanism*: [How it works in detail]
          *   *Context*: [When is this used/relevant?]
          *   *Implication* ↝ [What is the result?]
      *   **[Concept Name]**: [Detailed explanation...]

      ## ✎ Critical Vocabulary
      > ❞ **[Term]**: [Precise, academic definition. Do not shorten it.]
      > ❞ **[Term]**: [Precise, academic definition.]

      ## ❖ Real-World Examples & Application
      *   ✦ [Example 1: Describe a scenario where this knowledge is applied]
      *   ✦ [Example 2]

      ## ✳ Key Takeaways
      *   ▪ [Major point 1]
      *   ▪ [Major point 2]
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        temperature: 0.3,
        // Optional: increasing output tokens ensures we don't get cut off if we want long notes
        maxOutputTokens: 8192, 
      }
    });

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `❀ Notes: ${doc.title}`,
      content: response.text || "Failed to generate notes.",
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Notes Error:", error);
    throw error;
  }
};

export const generateQuiz = async (doc: Document, difficulty: 'easy' | 'medium' | 'hard'): Promise<Quiz> => {
  const ai = getAiClient();
  try {
    const filePart = await getFilePart(doc);
    const model = "gemini-3-flash-preview";

    const prompt = `
      Generate a quiz with 5 multiple choice questions based on the document.
      Difficulty: ${difficulty}.
      Return the output in strictly valid JSON format matching this schema:
      {
        "questions": [
          {
            "question": "string",
            "options": ["string", "string", "string", "string"],
            "correctAnswerIndex": number (0-3),
            "explanation": "string"
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  correctAnswerIndex: { type: Type.INTEGER },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswerIndex", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonText = response.text || "{}";
    const parsed = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)} Quiz: ${doc.title}`,
      questions: parsed.questions?.map((q: any) => ({...q, id: crypto.randomUUID()})) || [],
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Quiz Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { FileText, Sparkles, RefreshCw, Copy, Check, Highlighter, Star } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Document, Note } from '../types';
import { generateStudyNotes } from '../services/gemini';
import { saveNote, getNotesByDocumentId } from '../services/storage';

interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const load = async () => {
      const savedNotes = await getNotesByDocumentId(document.id);
      setNotes(savedNotes);
      if (savedNotes.length > 0) {
        setActiveNote(savedNotes[0]);
      } else {
        setActiveNote(null);
      }
    };
    load();
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setProgress(0);

    // Simulate progress
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 90) return prev;
        // Random increment between 1 and 3
        return prev + Math.floor(Math.random() * 3) + 1;
      });
    }, 400);

    try {
      const newNote = await generateStudyNotes(document);

      // Complete progress
      clearInterval(interval);
      setProgress(100);

      // Small delay to let user see 100%
      await new Promise(resolve => setTimeout(resolve, 500));

      await saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
      setProgress(0);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex gap-6">
      {/* Sidebar List */}
      <div className="w-72 flex-shrink-0 flex flex-col gap-4 animate-slide-up">
        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className={`w-full relative overflow-hidden bg-white hover:bg-gray-50 text-gray-800 py-4 px-6 rounded-2xl shadow-lg shadow-gray-100 border border-white/60 transition-all font-bold disabled:opacity-100 disabled:cursor-wait group hover:scale-[1.02] active:scale-95 flex flex-col justify-center min-h-[80px]`}
        >
