import { GoogleGenAI, Type } from "@google/genai";
import { Document, Quiz, Note } from '../types';

// Helper to get fresh API client
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert Blob/File to Base64
const fileToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g. "data:image/png;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

// Helper to prepare file part
const getFilePart = async (doc: Document) => {
  const base64Data = await fileToBase64(doc.file);
  return {
    inlineData: {
      mimeType: doc.mimeType,
      data: base64Data
    }
  };
};

export const generateChatResponse = async (
  doc: Document,
  history: { role: string; text: string }[],
  newMessage: string
): Promise<string> => {
  const ai = getAiClient();
  try {
    const filePart = await getFilePart(doc);

    // We use flash for chat for lower latency
    const model = "gemini-3-flash-preview";

    const systemInstruction = `
      You are 'Lumi', a cute and intelligent study assistant.
      Your task is to answer questions based ONLY on the provided document.
      - Explain concepts clearly and simply.
      - Expand ideas instead of summarizing them.
      - Use examples where helpful.
      - NEVER hallucinate or use outside knowledge.
      - If the answer is not found in the document, respond exactly with: "I couldn’t find this in your notes."
    `;

    const contents = [
      { role: 'user', parts: [filePart, { text: "Analyze this document for our session." }] },
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: newMessage }] }
    ];

    const response = await ai.models.generateContent({
      model,
      contents: contents, 
      config: {
        systemInstruction,
        temperature: 0.4,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

export const generateStudyNotes = async (doc: Document): Promise<Note> => {
  const ai = getAiClient();
  try {
    const filePart = await getFilePart(doc);
    const model = "gemini-3-pro-preview"; 

    // Updated prompt for deeper, non-summary content with specific aesthetics
    const prompt = `
      Act as an elite academic professor creating the ultimate "Deep Dive" study guide.

      OBJECTIVE:
      Extract knowledge from the document and format it into a comprehensive, textbook-quality study set.
      **DO NOT SUMMARIZE.** You must EXPAND on every concept. If the document mentions a term, define it, explain how it works, why it matters, and give an example.

      STYLE RULES:
      1. **Depth over Brevity:** Never write one sentence when three will explain it better. 
      2. **Logical Flow:** Use arrows (↝) to show cause-and-effect or process flow.
      3. **Aesthetics:** Use the specific symbols provided below to make it look like beautiful, handwritten Notion notes.

      SYMBOLS TO USE:
      - Headers: ❀, ꩜, ⚡, ❖
      - Bullets: ◦ (for main points), ▪ (for sub-points)
      - Arrows: ↝ (for logic flow), ⇢ (for examples)
      - Definitions: ❞
      - Key Points: ⋆, ✦

      REQUIRED MARKDOWN STRUCTURE:

      # ❀ [Creative & Descriptive Title]

      ## ꩜ Core Thesis & Context
      [Write a detailed paragraph explaining the main topic. Connect ideas using ↝.]

      ## ⚡ Deep Concept Breakdown
      [For every major concept, create a subsection]
      ### ✦ [Concept Name]
      *   **Definition**: [Full academic definition]
      *   **The Mechanism**: [How does it actually work? Step-by-step]
          *   Step 1 ↝ Step 2 ↝ Result
      *   **Why it Matters**: [Contextual importance]

      ## ✎ Critical Vocabulary
      > ❞ **[Term]**: [Deep definition. Do not shorten it.]
      > ❞ **[Term]**: [Deep definition.]

      ## ❖ Applied Knowledge & Examples
      *   **Scenario A**: [Describe a real-world application] ⇢ [Explain the outcome]
      *   **Scenario B**: [Another example]

      ## ✳ Master Takeaways
      *   ▪ [Complex insight 1]
      *   ▪ [Complex insight 2]
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        temperature: 0.3,
        // Increased max tokens to allow for "Deep" notes without cutting off
        maxOutputTokens: 8192, 
      }
    });

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `❀ Notes: ${doc.title}`,
      content: response.text || "Failed to generate notes.",
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Notes Error:", error);
    throw error;
  }
};

export const generateQuiz = async (doc: Document, difficulty: 'easy' | 'medium' | 'hard'): Promise<Quiz> => {
  const ai = getAiClient();
  try {
    const filePart = await getFilePart(doc);
    const model = "gemini-3-flash-preview";

    const prompt = `
      Generate a quiz with 5 multiple choice questions based on the document.
      Difficulty: ${difficulty}.
      Return the output in strictly valid JSON format matching this schema:
      {
        "questions": [
          {
            "question": "string",
            "options": ["string", "string", "string", "string"],
            "correctAnswerIndex": number (0-3),
            "explanation": "string"
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  correctAnswerIndex: { type: Type.INTEGER },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswerIndex", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonText = response.text || "{}";
    const parsed = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)} Quiz: ${doc.title}`,
      questions: parsed.questions?.map((q: any) => ({...q, id: crypto.randomUUID()})) || [],
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Quiz Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { FileText, Sparkles, RefreshCw, Copy, Check, Highlighter, Star } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Document, Note } from '../types';
import { generateStudyNotes } from '../services/gemini';
import { saveNote, getNotesByDocumentId } from '../services/storage';

interface NotesGeneratorProps {
  document: Document;
}

const NotesGenerator: React.FC<NotesGeneratorProps> = ({ document }) => {
  const [notes, setNotes] = useState<Note[]>([]);
  const [activeNote, setActiveNote] = useState<Note | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const load = async () => {
      const savedNotes = await getNotesByDocumentId(document.id);
      setNotes(savedNotes);
      if (savedNotes.length > 0) {
        setActiveNote(savedNotes[0]);
      } else {
        setActiveNote(null);
      }
    };
    load();
  }, [document.id]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setProgress(0);

    // Simulate progress: Fast at first, then slows down to wait for API
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 92) return prev; // Stall at 92%
        // Random increment
        const increment = prev < 50 ? Math.floor(Math.random() * 5) + 3 : Math.floor(Math.random() * 2) + 1;
        return Math.min(prev + increment, 92);
      });
    }, 400);

    try {
      const newNote = await generateStudyNotes(document);

      // Jump to 100% when done
      clearInterval(interval);
      setProgress(100);

      // Small visual delay before showing result
      await new Promise(resolve => setTimeout(resolve, 600));

      await saveNote(newNote);
      setNotes(prev => [newNote, ...prev]);
      setActiveNote(newNote);
    } catch (error) {
      console.error(error);
      alert("Failed to generate notes. Please check API key.");
    } finally {
      setIsGenerating(false);
      setProgress(0);
    }
  };

  const copyToClipboard = () => {
    if (!activeNote) return;
    navigator.clipboard.writeText(activeNote.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex gap-6">
      {/* Sidebar List */}
      <div className="w-72 flex-shrink-0 flex flex-col gap-4 animate-slide-up">
        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className={`w-full relative overflow-hidden bg-white hover:bg-gray-50 text-gray-800 py-4 px-6 rounded-2xl shadow-lg shadow-gray-100 border border-white/60 transition-all font-bold disabled:opacity-100 disabled:cursor-wait group hover:scale-[1.02] active:scale-95 flex flex-col justify-center min-h-[80px]`}
        >
          {isGenerating ? (
            <div className="w-full relative z-10">
               <div className="flex justify-between items-center mb-2 text-xs font-black uppercase tracking-widest text-rose-500">
                  <span className="flex items-center gap-2"><RefreshCw size={12} className="animate-spin" /> Thinking</span>
                  <span>{progress}%</span>
               </div>
               <div className="w-full h-2 bg-gray-100 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-gradient-to-r from-rose-400 to-rose-500 transition-all duration-300 ease-out" 
                    style={{ width: `${progress}%` }}
                  ></div>
               </div>
            </div>
          ) : (
            <div className="flex items-center justify-center gap-3">
               <Sparkles size={20} className="text-yellow-400 fill-yellow-400 group-hover:rotate-12 transition-transform" />
               <span>Create Magic Notes</span>
            </div>
          )}
        </button>

        <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
          {notes.length === 0 ? (
            <div className="text-center py-10 opacity-50 animate-fade-in">
                <FileText className="w-12 h-12 mx-auto mb-2" />
                <p className="font-bold text-sm">No notes found</p>
            </div>
          ) : (
            notes.map((note, idx) => (
              <button
                key={note.id}
                onClick={() => setActiveNote(note)}
                style={{ animationDelay: `${idx * 100}ms` }}
                className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 group animate-slide-up ${
                  activeNote?.id === note.id
                    ? 'bg-white border-rose-200 shadow-md shadow-rose-100 scale-[1.02]'
                    : 'bg-white/40 border-transparent hover:bg-white hover:shadow-sm'
                }`}
              >
                <div className="flex items-center gap-3 mb-1">
                  <div className={`p-2 rounded-lg transition-colors ${activeNote?.id === note.id ? 'bg-rose-100 text-rose-500' : 'bg-gray-100 text-gray-400'}`}>
                      <FileText size={16} />
                  </div>
                  <span className="font-bold text-xs text-gray-400 uppercase tracking-wide">{new Date(note.createdAt).toLocaleDateString()}</span>
                </div>
                <p className={`font-bold text-sm truncate transition-colors ${activeNote?.id === note.id ? 'text-gray-800' : 'text-gray-600'}`}>{note.title}</p>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main Content (Paper Look) */}
      <div className="flex-1 bg-[#fffdf0] rounded-[2rem] shadow-xl shadow-gray-200/50 flex flex-col overflow-hidden relative border border-[#f0e6d2] animate-scale-in">
        {/* Paper Texture Decor */}
        <div className="absolute top-0 left-0 w-full h-8 bg-repeat-x opacity-20" style={{backgroundImage: 'linear-gradient(135deg, #000 5%, transparent 5%), linear-gradient(-135deg, #000 5%, transparent 5%)', backgroundSize: '10px 10px'}}></div>

        {activeNote ? (
          <>
            <div className="px-8 py-6 border-b border-[#e6dec8] flex items-center justify-between bg-[#fffef5]">
              <h2 className="font-hand text-3xl font-bold text-gray-800 truncate animate-fade-in">{activeNote.title}</h2>
              <button 
                onClick={copyToClipboard}
                className="flex items-center gap-2 text-xs font-bold uppercase tracking-wider text-gray-500 hover:text-gray-900 transition-all hover:scale-105 active:scale-95 px-4 py-2 rounded-full hover:bg-[#f0e6d2]"
              >
                {copied ? <Check size={16} className="text-green-500" /> : <Copy size={16} />}
                {copied ? 'Copied!' : 'Copy'}
              </button>
            </div>
            <div key={activeNote.id} className="flex-1 overflow-y-auto p-12 font-hand text-xl leading-loose text-gray-800 animate-fade-in">
              <ReactMarkdown 
                components={{
