// 1. MEMORY GAME
const MemoryGame = () => {
  const emojis = ['🐶', '🐱', '🐭', '🐹', '🐰', '🦊', '🐻', '🐼'];
  const [cards, setCards] = useState<{id: number, emoji: string, flipped: boolean, matched: boolean}[]>([]);
  const [flippedCards, setFlippedCards] = useState<number[]>([]);
  const [matches, setMatches] = useState(0);

  useEffect(() => {
    resetGame();
  }, []);

  const resetGame = () => {
    const shuffled = [...emojis, ...emojis]
      .sort(() => Math.random() - 0.5)
      .map((emoji, index) => ({ id: index, emoji, flipped: false, matched: false }));
    setCards(shuffled);
    setFlippedCards([]);
    setMatches(0);
  };

  const handleCardClick = (id: number) => {
    if (flippedCards.length === 2) return;
    const cardIndex = cards.findIndex(c => c.id === id);
    if (cards[cardIndex].flipped || cards[cardIndex].matched) return;

    const newCards = [...cards];
    newCards[cardIndex].flipped = true;
    setCards(newCards);

    const newFlipped = [...flippedCards, id];
    setFlippedCards(newFlipped);

    if (newFlipped.length === 2) {
      const card1 = newCards.find(c => c.id === newFlipped[0]);
      const card2 = newCards.find(c => c.id === newFlipped[1]);

      if (card1?.emoji === card2?.emoji) {
        setTimeout(() => {
          setCards(prev => prev.map(c => 
            newFlipped.includes(c.id) ? { ...c, matched: true } : c
          ));
          setFlippedCards([]);
          setMatches(m => m + 1);
        }, 500);
      } else {
        setTimeout(() => {
          setCards(prev => prev.map(c => 
            newFlipped.includes(c.id) ? { ...c, flipped: false } : c
          ));
          setFlippedCards([]);
        }, 1000);
      }
    }
  };

  return (
    <div className="flex flex-col items-center animate-fade-in">
      <div className="flex justify-between w-full max-w-sm mb-4">
        <h3 className="font-bold text-gray-700">Memory Match</h3>
        <button onClick={resetGame} className="text-xs bg-rose-100 text-rose-600 px-3 py-1 rounded-full font-bold">Restart</button>
      </div>
      <div className="grid grid-cols-4 gap-3 bg-white p-4 rounded-2xl shadow-sm">
        {cards.map(card => (
          <button
            key={card.id}
            onClick={() => handleCardClick(card.id)}
            className={`w-14 h-14 text-2xl flex items-center justify-center rounded-xl transition-all duration-300 transform ${card.flipped || card.matched ? 'bg-rose-100 rotate-0' : 'bg-gray-200 rotate-180 text-transparent'}`}
          >
            {(card.flipped || card.matched) ? card.emoji : '?'}
          </button>
        ))}
      </div>
      {matches === 8 && <div className="mt-4 text-green-500 font-bold animate-bounce">You won! 🎉</div>}
    </div>
  );
};

// 2. BUBBLE POP GAME
const BubblePopGame = () => {
  const [bubbles, setBubbles] = useState<{id: number, x: number, y: number, color: string}[]>([]);
  const [score, setScore] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      if (bubbles.length < 8) {
        setBubbles(prev => [
          ...prev, 
          { 
            id: Date.now(), 
            x: Math.random() * 80 + 10, 
            y: 100, 
            color: ['#fda4af', '#93c5fd', '#86efac', '#fde047'][Math.floor(Math.random() * 4)] 
          }
        ]);
      }
    }, 800);

    const moveInterval = setInterval(() => {
      setBubbles(prev => prev.map(b => ({...b, y: b.y - 2})).filter(b => b.y > -20));
    }, 50);

    return () => { clearInterval(interval); clearInterval(moveInterval); };
  }, [bubbles.length]);

  const popBubble = (id: number) => {
    setBubbles(prev => prev.filter(b => b.id !== id));
    setScore(s => s + 1);
  };

  return (
    <div className="w-full h-80 bg-blue-50/50 rounded-3xl relative overflow-hidden border border-blue-100 cursor-crosshair">
       <div className="absolute top-4 left-4 font-black text-blue-400 text-xl z-10">Score: {score}</div>
       {bubbles.map(b => (
         <button
           key={b.id}
           onClick={() => popBubble(b.id)}
           style={{ left: `${b.x}%`, top: `${b.y}%`, backgroundColor: b.color }}
           className="absolute w-12 h-12 rounded-full shadow-md border-2 border-white active:scale-90 transition-transform"
         />
       ))}
       <div className="absolute bottom-4 left-0 w-full text-center text-gray-400 text-sm font-bold pointer-events-none">Pop bubbles while you wait!</div>
    </div>
  );
};

