import { GoogleGenAI, Type } from "@google/genai";
import { Document, Quiz, Note } from '../types';

// Helper to get fresh API client
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  // Note: If you are using Vite, you might need import.meta.env.VITE_API_KEY depending on your config,
  // but strictly following instructions we use process.env.API_KEY.
  if (!apiKey) {
    console.error("API Key is missing. Ensure process.env.API_KEY is set.");
    throw new Error("API Key not found. Please check your environment variables.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert Blob/File to Base64
const fileToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g. "data:image/png;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

// Helper to prepare file part
const getFilePart = async (doc: Document) => {
  const base64Data = await fileToBase64(doc.file);
  return {
    inlineData: {
      mimeType: doc.mimeType,
      data: base64Data
    }
  };
};

export const generateChatResponse = async (
  doc: Document,
  history: { role: string; text: string }[],
  newMessage: string
): Promise<string> => {
  try {
    const ai = getAiClient();
    const filePart = await getFilePart(doc);

    // We use flash for chat for lower latency
    const model = "gemini-3-flash-preview";

    const systemInstruction = `
      You are 'Lumi', a cute and intelligent study assistant.
      Your task is to answer questions based ONLY on the provided document.
      - Explain concepts clearly and simply.
      - Expand ideas instead of summarizing them.
      - Use examples where helpful.
      - NEVER hallucinate or use outside knowledge.
      - If the answer is not found in the document, respond exactly with: "I couldn’t find this in your notes."
    `;

    const contents = [
      { role: 'user', parts: [filePart, { text: "Analyze this document for our session." }] },
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: newMessage }] }
    ];

    const response = await ai.models.generateContent({
      model,
      contents: contents, 
      config: {
        systemInstruction,
        temperature: 0.4,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error: any) {
    console.error("Gemini Chat Error:", error);
    if (error.message?.includes('401') || error.status === 401) {
      return "Error: Invalid API Key. Please check your authentication credentials.";
    }
    return "Sorry, I encountered an error processing your request.";
  }
};

export const generateStudyNotes = async (doc: Document): Promise<Note> => {
  try {
    const ai = getAiClient();
    const filePart = await getFilePart(doc);
    const model = "gemini-3-pro-preview"; 

    // Updated prompt for strict structural fidelity
    const prompt = `
      Act as an expert academic scribe. Your goal is to create a complete Study Companion for this document.

      CRITICAL INSTRUCTIONS FOR STRUCTURE:
      1. **FULL COVERAGE**: You must extract and generate notes for **EVERY** Chapter, Unit, and Section found in the document.
      2. **STRICT ORDER**: Follow the exact order of the document (e.g., Chapter 1 -> Chapter 2 -> Chapter 3). Do not reorder or group them.
      3. **EXACT TERMINOLOGY**: Use the exact chapter titles and headings found in the source text.
      4. **NO SKIPPING**: Do not summarize multiple chapters into one. Treat each chapter as a distinct, detailed entity.

      CONTENT STYLE:
      - **Deep & Comprehensive**: Do not create brief summaries. Expand on concepts.
      - **Textbook Quality**: Write as if writing a high-quality textbook or student study guide.
      - **Visual Hierarchy**: Use the symbols provided below.

      REQUIRED MARKDOWN FORMAT (Repeat for EACH Chapter/Unit):

      # ❀ [Exact Chapter Number & Title]

      ## ꩜ Chapter Overview
      [Detailed explanation of the chapter's core thesis. 3-4 sentences.]

      ## ⚡ Key Concepts & Analysis
      [Iterate through every major section in this chapter]
      ### ✦ [Section Title]
      *   **Core Concept**: [Deep definition and explanation]
      *   **Process/Mechanism**: Step 1 ↝ Step 2 ↝ Outcome
      *   **Why It Matters**: [Contextual importance]

      ## ✎ Vital Terminology
      > ❞ **[Term]**: [Exact definition from text]
      > ❞ **[Term]**: [Exact definition from text]

      ## ❖ Illustrative Examples
      *   [Detail specific examples, case studies, or scenarios mentioned in this chapter]

      ---
      [IMMEDIATELY PROCEED TO THE NEXT CHAPTER]
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        temperature: 0.2, // Low temperature for high fidelity
        maxOutputTokens: 8192, // Maximize output length for comprehensive notes
      }
    });

    if (!response.text) {
      throw new Error("Empty response from AI");
    }

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `❀ Notes: ${doc.title}`,
      content: response.text,
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Notes Error:", error);
    throw error;
  }
};

export const generateQuiz = async (doc: Document, difficulty: 'easy' | 'medium' | 'hard'): Promise<Quiz> => {
  try {
    const ai = getAiClient();
    const filePart = await getFilePart(doc);
    const model = "gemini-3-flash-preview";

    const prompt = `
      Generate a quiz with 5 multiple choice questions based on the document.
      Difficulty: ${difficulty}.
      Return the output in strictly valid JSON format matching this schema:
      {
        "questions": [
          {
            "question": "string",
            "options": ["string", "string", "string", "string"],
            "correctAnswerIndex": number (0-3),
            "explanation": "string"
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  correctAnswerIndex: { type: Type.INTEGER },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswerIndex", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonText = response.text || "{}";
    const parsed = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)} Quiz: ${doc.title}`,
      questions: parsed.questions?.map((q: any) => ({...q, id: crypto.randomUUID()})) || [],
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Quiz Error:", error);
    throw error;
  }
};

