import React, { useCallback, useState } from 'react';
import { Upload, FileText, Check, AlertCircle, X, Cloud, Image, FileType } from 'lucide-react';

interface DocumentUploadProps {
  onUpload: (file: File) => Promise<void>;
  onClose: () => void;
}

const DocumentUpload: React.FC<DocumentUploadProps> = ({ onUpload, onClose }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setIsDragging(true);
    } else if (e.type === 'dragleave') {
      setIsDragging(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      validateAndSetFile(e.dataTransfer.files[0]);
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      validateAndSetFile(e.target.files[0]);
    }
  };

  const validateAndSetFile = (file: File) => {
    const allowedTypes = [
      'application/pdf',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document', // docx
      'application/vnd.openxmlformats-officedocument.presentationml.presentation', // pptx
      'text/plain',
      'text/markdown',
      'text/csv',
      'text/html',
      'text/xml',
      'text/rtf',
      'application/rtf',
      'application/json',
      'text/javascript',
      'application/javascript',
      'text/x-python',
      'application/x-python',
      'text/css',
      'image/png',
      'image/jpeg',
      'image/webp',
      'image/heic'
    ];

    const allowedExtensions = ['.md', '.py', '.js', '.ts', '.tsx', '.jsx', '.json', '.xml', '.csv', '.html', '.css', '.txt', '.pdf', '.docx', '.pptx', '.png', '.jpg', '.jpeg', '.webp'];

    const fileExt = '.' + file.name.split('.').pop()?.toLowerCase();
    const isTypeAllowed = allowedTypes.includes(file.type) || allowedExtensions.includes(fileExt);

    if (!isTypeAllowed) {
      setError('Oops! Supported formats: PDF, DOCX, PPTX, Text, Code, Images.');
      return;
    }

    // 20MB limit
    if (file.size > 20 * 1024 * 1024) {
      setError('Whoa! That file is too big (Max 20MB).');
      return;
    }
    setError(null);
    setFile(file);
  };

  const handleSubmit = async () => {
    if (!file) return;
    setUploading(true);
    try {
      await onUpload(file);
      onClose();
    } catch (err) {
      console.error(err);
      setError('Something went wrong. Try again?');
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-md">
      <div className="bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden relative border border-white/50 animate-float-delayed">
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 p-2 bg-gray-100 rounded-full text-gray-500 hover:bg-gray-200 transition-colors"
        >
          <X size={20} />
        </button>

        <div className="p-10">
          <div className="text-center mb-8">
            <h2 className="text-3xl font-black text-gray-800 mb-2">Feed Lumi</h2>
            <p className="text-gray-500 font-medium">Upload your study material.</p>
          </div>

          <div
            onDragEnter={handleDrag}
            onDragLeave={handleDrag}
            onDragOver={handleDrag}
            onDrop={handleDrop}
            className={`
              relative border-4 border-dashed rounded-3xl p-10 text-center transition-all duration-300
              ${isDragging 
                ? 'border-rose-400 bg-rose-50 scale-105' 
                : file 
                  ? 'border-green-400 bg-green-50' 
                  : 'border-gray-200 hover:border-rose-300 hover:bg-white'}
            `}
          >
            <input
              type="file"
              id="file-upload"
              className="hidden"
              accept=".pdf,.png,.jpg,.jpeg,.webp,.txt,.md,.csv,.html,.xml,.json,.docx,.pptx,.rtf,.js,.py,.css"
              onChange={handleChange}
            />

            {file ? (
              <div className="flex flex-col items-center animate-bounce">
                <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-500 shadow-sm">
                  <Check size={40} strokeWidth={3} />
                </div>
                <p className="font-bold text-gray-800 text-lg truncate max-w-xs">{file.name}</p>
                <p className="text-sm font-bold text-green-600 mt-1">Ready to go!</p>
                <button 
                  onClick={() => setFile(null)}
                  className="text-xs font-bold text-gray-400 mt-4 hover:text-red-500 transition-colors"
                >
                  Change file
                </button>
              </div>
            ) : (
              <div className="flex flex-col items-center">
                <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center mb-6 text-blue-400 shadow-inner relative">
                  <Cloud size={48} strokeWidth={2.5} />
                  <div className="absolute -bottom-2 -right-2 bg-white p-1.5 rounded-full shadow-sm">
                     <Image size={16} className="text-purple-400" />
                  </div>
                  <div className="absolute -top-2 -left-2 bg-white p-1.5 rounded-full shadow-sm">
                     <FileType size={16} className="text-orange-400" />
                  </div>
                </div>
                <p className="font-bold text-gray-800 text-lg">Drag & Drop</p>
                <p className="text-sm font-bold text-gray-400 mt-1 mb-6">PDF, DOCX, PPTX, Text, Images</p>
                <label 
                  htmlFor="file-upload" 
                  className="px-6 py-3 bg-white border-2 border-gray-200 rounded-xl font-bold text-gray-600 hover:border-blue-400 hover:text-blue-500 cursor-pointer transition-all shadow-sm"
                >
                  Choose File
                </label>
              </div>
            )}
          </div>

          {error && (
            <div className="mt-6 p-4 bg-red-50 text-red-600 font-bold text-sm rounded-2xl flex items-center gap-3 animate-pulse">
              <AlertCircle size={20} />
              {error}
            </div>
          )}

          <div className="mt-8">
            <button
              onClick={handleSubmit}
              disabled={!file || uploading}
              className="w-full py-4 bg-gray-900 hover:bg-gray-800 text-white rounded-2xl shadow-xl shadow-gray-200 transition-all font-bold text-lg disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"
            >
              {uploading ? (
                <>
                  <div className="w-5 h-5 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
                  Saving...
                </>
              ) : (
                'Upload & Shine'
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DocumentUpload;

import { GoogleGenAI, Type } from "@google/genai";
import { Document, Quiz, Note } from '../types';
// @ts-ignore
import mammoth from 'mammoth';
// @ts-ignore
import JSZip from 'jszip';

// Helper to get fresh API client
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API Key is missing. Ensure process.env.API_KEY is set.");
    throw new Error("API Key not found. Please check your environment variables.");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert Blob/File to Base64 (for standard supported formats)
const fileToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

// Helper to extract text from DOCX using mammoth
const extractDocxText = async (file: File): Promise<string> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value;
  } catch (error) {
    console.error("DOCX extraction error:", error);
    return "Error extracting text from DOCX file.";
  }
};

// Helper to extract text from PPTX using JSZip (basic slide text extraction)
const extractPptxText = async (file: File): Promise<string> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    const zip = await JSZip.loadAsync(arrayBuffer);
    let textContent = "";

    // Find all slide XML files
    const slideFiles = Object.keys(zip.files).filter(fileName => 
      fileName.startsWith("ppt/slides/slide") && fileName.endsWith(".xml")
    );

    // Sort logically (slide1, slide2, etc.)
    slideFiles.sort((a, b) => {
      const numA = parseInt(a.match(/\d+/)?.[0] || "0");
      const numB = parseInt(b.match(/\d+/)?.[0] || "0");
      return numA - numB;
    });

    for (const fileName of slideFiles) {
      const xmlString = await zip.files[fileName].async("string");
      // Simple regex to extract text within <a:t> tags
      const slideText = xmlString.match(/<a:t>([^<]*)<\/a:t>/g)
        ?.map((tag: string) => tag.replace(/<\/?a:t>/g, ""))
        .join(" ") || "";

      if (slideText.trim()) {
        textContent += `[SLIDE]: ${slideText}\n\n`;
      }
    }

    return textContent || "No text found in presentation slides.";
  } catch (error) {
    console.error("PPTX extraction error:", error);
    return "Error extracting text from PPTX file.";
  }
};

// Helper to prepare file part
const getFilePart = async (doc: Document) => {
  const mimeType = doc.mimeType.toLowerCase();
  const name = doc.title.toLowerCase();

  // Handle DOCX -> Extract Text -> Send as plain text
  if (mimeType.includes('wordprocessingml') || name.endsWith('.docx')) {
    const text = await extractDocxText(doc.file);
    return {
      inlineData: {
        mimeType: 'text/plain',
        data: btoa(unescape(encodeURIComponent(text))) // text to base64 safely
      }
    };
  }

  // Handle PPTX -> Extract Text -> Send as plain text
  if (mimeType.includes('presentationml') || name.endsWith('.pptx')) {
    const text = await extractPptxText(doc.file);
    return {
      inlineData: {
        mimeType: 'text/plain',
        data: btoa(unescape(encodeURIComponent(text)))
      }
    };
  }

  // Handle Standard Text Formats supported by Gemini but sometimes easier as plain text
  // Actually Gemini supports these mimetypes usually, but text/plain is safest for inline data if simple.
  // However, PDF and Images MUST go as their native type.
  const isImageOrPdf = mimeType.includes('pdf') || mimeType.includes('image');

  if (isImageOrPdf) {
     const base64Data = await fileToBase64(doc.file);
     return {
       inlineData: {
         mimeType: doc.mimeType,
         data: base64Data
       }
     };
  }

  // For other text formats (txt, csv, json, md, html, xml, js, py)
  // We read as text and send as text/plain or specific type if widely supported.
  // Using simple text read is safer for generic 'text/*' types to ensure encoding is correct in base64.
  const text = await doc.file.text();
  return {
    inlineData: {
      mimeType: 'text/plain', // Simplifies processing for the model
      data: btoa(unescape(encodeURIComponent(text)))
    }
  };
};

export const generateChatResponse = async (
  doc: Document,
  history: { role: string; text: string }[],
  newMessage: string
): Promise<string> => {
  try {
    const ai = getAiClient();
    const filePart = await getFilePart(doc);

    // We use flash for chat for lower latency
    const model = "gemini-3-flash-preview";

    const systemInstruction = `
      You are 'Lumi', a cute and intelligent study assistant.
      Your task is to answer questions based ONLY on the provided document.
      - Explain concepts clearly and simply.
      - Expand ideas instead of summarizing them.
      - Use examples where helpful.
      - NEVER hallucinate or use outside knowledge.
      - If the answer is not found in the document, respond exactly with: "I couldn’t find this in your notes."
    `;

    const contents = [
      { role: 'user', parts: [filePart, { text: "Analyze this document for our session." }] },
      ...history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      })),
      { role: 'user', parts: [{ text: newMessage }] }
    ];

    const response = await ai.models.generateContent({
      model,
      contents: contents, 
      config: {
        systemInstruction,
        temperature: 0.4,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error: any) {
    console.error("Gemini Chat Error:", error);
    if (error.message?.includes('401') || error.status === 401) {
      return "Error: Invalid API Key. Please check your authentication credentials.";
    }
    return "Sorry, I encountered an error processing your request.";
  }
};

export const generateStudyNotes = async (doc: Document): Promise<Note> => {
  try {
    const ai = getAiClient();
    const filePart = await getFilePart(doc);
    const model = "gemini-3-pro-preview"; 

    // Updated prompt for strict structural fidelity
    const prompt = `
      Act as an expert academic scribe. Your goal is to create a complete Study Companion for this document.

      CRITICAL INSTRUCTIONS FOR STRUCTURE:
      1. **FULL COVERAGE**: You must extract and generate notes for **EVERY** Chapter, Unit, and Section found in the document.
      2. **STRICT ORDER**: Follow the exact order of the document (e.g., Chapter 1 -> Chapter 2 -> Chapter 3). Do not reorder or group them.
      3. **EXACT TERMINOLOGY**: Use the exact chapter titles and headings found in the source text.
      4. **NO SKIPPING**: Do not summarize multiple chapters into one. Treat each chapter as a distinct, detailed entity.

      CONTENT STYLE:
      - **Deep & Comprehensive**: Do not create brief summaries. Expand on concepts.
      - **Textbook Quality**: Write as if writing a high-quality textbook or student study guide.
      - **Visual Hierarchy**: Use the symbols provided below.

      REQUIRED MARKDOWN FORMAT (Repeat for EACH Chapter/Unit):

      # ❀ [Exact Chapter Number & Title]

      ## ꩜ Chapter Overview
      [Detailed explanation of the chapter's core thesis. 3-4 sentences.]

      ## ⚡ Key Concepts & Analysis
      [Iterate through every major section in this chapter]
      ### ✦ [Section Title]
      *   **Core Concept**: [Deep definition and explanation]
      *   **Process/Mechanism**: Step 1 ↝ Step 2 ↝ Outcome
      *   **Why It Matters**: [Contextual importance]

      ## ✎ Vital Terminology
      > ❞ **[Term]**: [Exact definition from text]
      > ❞ **[Term]**: [Exact definition from text]

      ## ❖ Illustrative Examples
      *   [Detail specific examples, case studies, or scenarios mentioned in this chapter]

      ---
      [IMMEDIATELY PROCEED TO THE NEXT CHAPTER]
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        temperature: 0.2, // Low temperature for high fidelity
        maxOutputTokens: 8192, // Maximize output length for comprehensive notes
      }
    });

    if (!response.text) {
      throw new Error("Empty response from AI");
    }

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `❀ Notes: ${doc.title}`,
      content: response.text,
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Notes Error:", error);
    throw error;
  }
};

export const generateQuiz = async (doc: Document, difficulty: 'easy' | 'medium' | 'hard'): Promise<Quiz> => {
  try {
    const ai = getAiClient();
    const filePart = await getFilePart(doc);
    const model = "gemini-3-flash-preview";

    const prompt = `
      Generate a quiz with 5 multiple choice questions based on the document.
      Difficulty: ${difficulty}.
      Return the output in strictly valid JSON format matching this schema:
      {
        "questions": [
          {
            "question": "string",
            "options": ["string", "string", "string", "string"],
            "correctAnswerIndex": number (0-3),
            "explanation": "string"
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [filePart, { text: prompt }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  },
                  correctAnswerIndex: { type: Type.INTEGER },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswerIndex", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonText = response.text || "{}";
    const parsed = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      documentId: doc.id,
      title: `${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)} Quiz: ${doc.title}`,
      questions: parsed.questions?.map((q: any) => ({...q, id: crypto.randomUUID()})) || [],
      createdAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Gemini Quiz Error:", error);
    throw error;
  }
};

