                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-rose-100 rounded-full flex items-center justify-center animate-spin-slow">
                     <RefreshCw className="text-rose-500 animate-spin" size={20} />
                  </div>
                  <div>
