            <button 
              onClick={onLogout}
              className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-rose-500 hover:bg-rose-50 rounded-xl transition-all btn-bounce"
            >
              <LogOut size={18} />
