            </button>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 min-w-0 h-screen overflow-auto pt-24 lg:pt-6 px-4 lg:pr-6 pb-6 relative z-10 custom-scrollbar">
        <div className="h-full rounded-[2.5rem] overflow-hidden">
          {children}
