      </main>

      {/* Mobile Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-gray-900/20 backdrop-blur-sm z-10 lg:hidden animate-fade-in"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { Layers, Sparkles, RefreshCw, ChevronLeft, ChevronRight, RotateCw, Plus } from 'lucide-react';
import { Document, FlashcardSet } from '../types';
import { generateFlashcards } from '../services/gemini';
import { saveFlashcardSet, getFlashcardSetsByDocumentId } from '../services/storage';

interface FlashcardGeneratorProps {
  document: Document;
}

const FlashcardGenerator: React.FC<FlashcardGeneratorProps> = ({ document }) => {
  const [sets, setSets] = useState<FlashcardSet[]>([]);
  const [activeSet, setActiveSet] = useState<FlashcardSet | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);

  // Card Game State
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  useEffect(() => {
    const load = async () => {
      const saved = await getFlashcardSetsByDocumentId(document.id);
      setSets(saved);
      if (saved.length > 0) setActiveSet(saved[0]);
    };
    load();
  }, [document.id]);

  useEffect(() => {
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [activeSet]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setProgress(0);
    const interval = setInterval(() => setProgress(p => Math.min(p + 10, 90)), 200);

    try {
      const newSet = await generateFlashcards(document);
      clearInterval(interval);
      setProgress(100);
      await new Promise(r => setTimeout(r, 500));

      await saveFlashcardSet(newSet);
      setSets(prev => [newSet, ...prev]);
      setActiveSet(newSet);
    } catch (error: any) {
      console.error(error);
      alert(error.message || "Failed to generate flashcards.");
    } finally {
      setIsGenerating(false);
      setProgress(0);
    }
  };

  const nextCard = () => {
    if (!activeSet) return;
    setIsFlipped(false);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % activeSet.cards.length);
    }, 200);
  };

  const prevCard = () => {
    if (!activeSet) return;
    setIsFlipped(false);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev - 1 + activeSet.cards.length) % activeSet.cards.length);
    }, 200);
  };

  return (
    <div className="h-full flex gap-6 relative">
      {/* Sidebar */}
      <div className="w-72 flex-shrink-0 flex flex-col gap-4 animate-slide-up">
        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className="w-full bg-white hover:bg-gray-50 text-gray-800 py-4 px-6 rounded-2xl shadow-lg border border-white/60 transition-all font-bold group flex flex-col items-center justify-center min-h-[80px]"
        >
          {isGenerating ? (
            <div className="flex flex-col items-center w-full">
               <div className="flex items-center gap-2 text-rose-500 mb-2">
                 <RefreshCw className="animate-spin" size={18} />
                 <span className="text-xs font-black uppercase tracking-widest">Brewing...</span>
               </div>
               <div className="w-full h-1 bg-gray-100 rounded-full overflow-hidden">
                 <div className="h-full bg-rose-400 transition-all duration-300" style={{width: `${progress}%`}}></div>
               </div>
            </div>
          ) : (
             <div className="flex items-center gap-2">
                <Layers className="text-purple-400" />
                <span>New Flashcards</span>
             </div>
          )}
        </button>

        <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
          {sets.length === 0 ? (
            <div className="text-center py-10 opacity-50">
              <Layers className="w-12 h-12 mx-auto mb-2" />
              <p className="font-bold text-sm">No decks yet</p>
            </div>
          ) : (
            sets.map((set, idx) => (
              <button
                key={set.id}
                onClick={() => setActiveSet(set)}
                className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 animate-slide-up ${
                  activeSet?.id === set.id
                    ? 'bg-white border-purple-200 shadow-md scale-[1.02]'
                    : 'bg-white/40 border-transparent hover:bg-white'
                }`}
                style={{ animationDelay: `${idx * 50}ms` }}
              >
                <div className="flex items-center gap-2 mb-1">
                   <div className="w-2 h-2 rounded-full bg-purple-400"></div>
                   <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{set.cards.length} Cards</span>
                </div>
                <p className="font-bold text-sm text-gray-800 truncate">{set.title}</p>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main Area */}
      <div className="flex-1 bg-[#fffdf0] rounded-[2.5rem] shadow-xl border border-[#f0e6d2] flex flex-col relative overflow-hidden animate-scale-in">
        <div className="absolute top-0 left-0 w-full h-full opacity-30 pointer-events-none" 
             style={{backgroundImage: 'radial-gradient(#e5e7eb 1px, transparent 1px)', backgroundSize: '20px 20px'}}></div>

        {!activeSet ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 animate-fade-in">
             <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-6 shadow-lg animate-float">
                <Layers size={40} className="text-purple-400" />
             </div>
             <p className="font-hand text-2xl text-gray-600">Generate a deck to start flipping!</p>
          </div>
        ) : (
          <div className="flex flex-col h-full items-center justify-center p-8 z-10">
            {/* Header / Progress */}
            <div className="absolute top-8 w-full px-12 flex justify-between items-center">
              <h2 className="font-bold text-gray-800 text-lg opacity-60 truncate max-w-md">{activeSet.title}</h2>
              <div className="bg-white/80 backdrop-blur px-4 py-1 rounded-full border border-gray-200 font-mono text-sm font-bold text-gray-600 shadow-sm">
                 {currentIndex + 1} / {activeSet.cards.length}
              </div>
            </div>

            {/* Card Container */}
            <div className="relative w-full max-w-2xl aspect-[3/2] perspective-1000 group">
              <div 
                className={`w-full h-full relative transition-all duration-700 preserve-3d cursor-pointer ${isFlipped ? 'rotate-y-180' : ''}`}
                onClick={() => setIsFlipped(!isFlipped)}
              >
                 {/* Front */}
                 <div className="absolute inset-0 backface-hidden bg-white rounded-3xl shadow-2xl border border-white/60 flex flex-col items-center justify-center p-12 text-center hover:shadow-purple-100/50 transition-shadow">
                    <span className="absolute top-6 left-6 text-xs font-black text-purple-400 uppercase tracking-widest">Question</span>
                    <h3 className="text-3xl md:text-4xl font-bold text-gray-800 leading-tight">
                       {activeSet.cards[currentIndex].front}
                    </h3>
                    <div className="absolute bottom-6 text-gray-400 text-sm font-bold flex items-center gap-2 animate-pulse">
                       <RotateCw size={14} /> Click to flip
                    </div>
                 </div>

                 {/* Back */}
                 <div className="absolute inset-0 backface-hidden rotate-y-180 bg-gradient-to-br from-gray-900 to-gray-800 text-white rounded-3xl shadow-2xl flex flex-col items-center justify-center p-12 text-center">
                    <span className="absolute top-6 left-6 text-xs font-black text-purple-300 uppercase tracking-widest">Answer</span>
                    <p className="text-xl md:text-2xl font-medium leading-relaxed">
                       {activeSet.cards[currentIndex].back}
                    </p>
                 </div>
              </div>
            </div>

            {/* Controls */}
            <div className="mt-10 flex items-center gap-6">
               <button 
                 onClick={prevCard}
                 className="p-4 bg-white rounded-full text-gray-600 hover:text-gray-900 shadow-lg hover:scale-110 active:scale-95 transition-all"
               >
                 <ChevronLeft size={24} />
               </button>

               <button 
                 onClick={() => setIsFlipped(!isFlipped)}
                 className="px-8 py-3 bg-purple-100 text-purple-600 rounded-xl font-bold hover:bg-purple-200 transition-colors"
               >
                 Flip Card
               </button>

               <button 
                 onClick={nextCard}
                 className="p-4 bg-white rounded-full text-gray-600 hover:text-gray-900 shadow-lg hover:scale-110 active:scale-95 transition-all"
               >
                 <ChevronRight size={24} />
               </button>
            </div>
          </div>
        )}
      </div>

      <style>{`
        .perspective-1000 { perspective: 1000px; }
        .preserve-3d { transform-style: preserve-3d; }
        .backface-hidden { backface-visibility: hidden; }
        .rotate-y-180 { transform: rotateY(180deg); }
      `}</style>
    </div>
  );
};

export default FlashcardGenerator;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Auth from './components/Auth';
import LandingPage from './components/LandingPage';
import DocumentUpload from './components/DocumentUpload';
import ChatInterface from './components/ChatInterface';
import NotesGenerator from './components/NotesGenerator';
import QuizGenerator from './components/QuizGenerator';
import FlashcardGenerator from './components/FlashcardGenerator';
import { getCurrentUser, loginUser, logoutUser, saveDocument, getDocuments, getDocumentById } from './services/storage';
import { User, AppView, Document } from './types';
import { Cloud, ArrowRight, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showLanding, setShowLanding] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [isUploadOpen, setIsUploadOpen] = useState(false);
  const [activeDocumentId, setActiveDocumentId] = useState<string | null>(null);
  const [activeDocument, setActiveDocument] = useState<Document | null>(null);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const init = async () => {
      const storedUser = getCurrentUser();
      if (storedUser) {
        setUser(storedUser);
        setShowLanding(false);
      }
      await refreshDocuments();
      setIsLoading(false);
    };
    init();
  }, []);

  // Update active document object when ID changes
  useEffect(() => {
    const fetchDoc = async () => {
      if (activeDocumentId) {
        const doc = await getDocumentById(activeDocumentId);
        setActiveDocument(doc || null);
      } else {
        setActiveDocument(null);
      }
    };
    fetchDoc();
  }, [activeDocumentId]);

  const refreshDocuments = async () => {
    const docs = await getDocuments();
    setDocuments(docs);
    if (docs.length > 0 && !activeDocumentId) {
      setActiveDocumentId(docs[0].id);
    }
  };

  const handleLogin = async (email: string, name: string) => {
    const newUser = await loginUser(email, name);
    setUser(newUser);
    setShowLanding(false);
  };

  const handleLogout = () => {
    logoutUser();
    setUser(null);
    setShowLanding(true);
  };

  const handleUpload = async (file: File) => {
    try {
      const newDoc = await saveDocument(file);
      setDocuments(prev => [...prev, newDoc]);
      setActiveDocumentId(newDoc.id);
      setCurrentView(AppView.NOTES);
    } catch (e) {
      console.error("Upload failed", e);
      alert("Failed to save document. It might be too large.");
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#fff0f3]">
         <div className="relative animate-pop-in">
            <div className="w-16 h-16 border-4 border-rose-200 border-t-rose-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center">
               <Sparkles size={20} className="text-rose-500 animate-pulse" />
            </div>
         </div>
      </div>
    );
  }

  // Render Logic
  if (showLanding && !user) {
    return <LandingPage onGetStarted={() => setShowLanding(false)} />;
  }

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <Layout
      user={user}
      currentView={currentView}
      onNavigate={setCurrentView}
      onLogout={handleLogout}
      onUploadClick={() => setIsUploadOpen(true)}
    >
      {/* View Routing with Animations */}
      {currentView === AppView.DASHBOARD && (
        <div key="dashboard" className="p-4 lg:p-10 animate-slide-up">
          <div className="mb-10">
             <div className="inline-block bg-white/50 backdrop-blur-sm px-4 py-2 rounded-full border border-white/60 mb-4 animate-float">
                <span className="text-sm font-bold text-gray-500">✨ Ready to learn?</span>
             </div>
             <h1 className="text-4xl lg:text-5xl font-black text-gray-800 mb-3 animate-fade-in stagger-1 opacity-0">Hi, {user.name}</h1>
             <p className="text-gray-500 font-medium text-lg animate-fade-in stagger-2 opacity-0">Pick a document to start your session.</p>
          </div>

          {documents.length === 0 ? (
            <div className="bg-white/60 backdrop-blur-md rounded-[3rem] p-16 text-center border-2 border-dashed border-gray-300/60 hover:border-rose-300 transition-all duration-300 group animate-scale-in">
              <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform duration-300">
                <Cloud className="text-rose-400" size={48} strokeWidth={2.5} />
              </div>
              <h3 className="text-2xl font-black text-gray-800 mb-3">Your library is empty</h3>
              <p className="text-gray-500 mb-8 max-w-md mx-auto font-medium">Upload your first PDF and watch Lumi turn it into magic study material.</p>
              <button
                onClick={() => setIsUploadOpen(true)}
                className="px-8 py-4 bg-gray-900 hover:bg-gray-800 text-white rounded-2xl font-bold shadow-xl shadow-rose-100 transition-all hover:-translate-y-1 active:scale-95"
              >
                Upload First PDF
              </button>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in stagger-3 opacity-0">
              {documents.map((doc, idx) => (
                <div 
                  key={doc.id} 
                  style={{ animationDelay: `${idx * 100}ms` }}
                  className={`group relative bg-white/70 backdrop-blur-md rounded-[2.5rem] p-8 border transition-all cursor-pointer hover:shadow-xl hover:-translate-y-2 duration-300 animate-slide-up ${activeDocumentId === doc.id ? 'border-rose-400 ring-4 ring-rose-100 shadow-lg shadow-rose-100' : 'border-white/50 hover:border-rose-200'}`}
                  onClick={() => setActiveDocumentId(doc.id)}
                >
                  <div className="flex items-start justify-between mb-6">
                    <div className="w-14 h-14 bg-gradient-to-br from-rose-100 to-orange-100 text-rose-500 rounded-2xl flex items-center justify-center group-hover:rotate-6 transition-transform shadow-inner">
                      <Cloud size={28} strokeWidth={2.5} />
                    </div>
                    {activeDocumentId === doc.id && (
                      <span className="text-[10px] font-black uppercase tracking-widest bg-rose-500 text-white px-3 py-1 rounded-full shadow-md animate-pop-in">Active</span>
                    )}
                  </div>
                  <h3 className="text-xl font-bold text-gray-800 truncate mb-2">{doc.title}</h3>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-wide mb-8">Added {new Date(doc.uploadDate).toLocaleDateString()}</p>

                  <div className="flex gap-3">
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.CHAT); }}
                      className="flex-1 py-3 text-sm font-bold text-gray-600 bg-white border border-gray-100 rounded-xl hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm hover:shadow-md active:scale-95"
                    >
                      Chat
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveDocumentId(doc.id); setCurrentView(AppView.NOTES); }}
                      className="flex-1 py-3 text-sm font-bold text-gray-600 bg-white border border-gray-100 rounded-xl hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm hover:shadow-md active:scale-95"
                    >
                      Notes
                    </button>
                  </div>
                </div>
              ))}

              <button 
                onClick={() => setIsUploadOpen(true)}
                className="bg-white/40 backdrop-blur-sm rounded-[2.5rem] p-6 border-2 border-dashed border-gray-300 hover:border-rose-400 hover:bg-rose-50/50 transition-all flex flex-col items-center justify-center text-gray-400 hover:text-rose-500 min-h-[240px] group animate-slide-up"
                style={{ animationDelay: `${documents.length * 100}ms` }}
              >
                <div className="w-16 h-16 rounded-full bg-white border-2 border-current flex items-center justify-center mb-4 group-hover:scale-110 transition-transform shadow-sm">
                  <span className="text-3xl font-light pb-1">+</span>
                </div>
                <span className="font-bold text-lg">Add New</span>
              </button>
            </div>
          )}
        </div>
      )}

      {currentView !== AppView.DASHBOARD && !activeDocument && (
        <div key="empty" className="flex flex-col items-center justify-center h-full text-center p-8 animate-fade-in">
          <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mb-6 animate-pulse">
            <Cloud size={40} className="text-gray-400" />
          </div>
          <h2 className="text-2xl font-black text-gray-800 mb-2">Nothing selected</h2>
          <p className="text-gray-500 font-medium mb-6">Select a document from the library to start.</p>
          <button 
            onClick={() => setCurrentView(AppView.DASHBOARD)}
            className="flex items-center gap-2 px-6 py-3 bg-gray-900 text-white rounded-xl font-bold hover:bg-gray-800 transition-all hover:scale-105 active:scale-95"
          >
            Go to Library <ArrowRight size={16} />
          </button>
        </div>
      )}

      {activeDocument && (
        <div key={currentView} className="h-full animate-slide-up">
          {currentView === AppView.CHAT && <ChatInterface document={activeDocument} />}
          {currentView === AppView.NOTES && <NotesGenerator document={activeDocument} />}
          {currentView === AppView.QUIZ && <QuizGenerator document={activeDocument} />}
          {currentView === AppView.FLASHCARDS && <FlashcardGenerator document={activeDocument} />}
        </div>
      )}

      {isUploadOpen && (
        <DocumentUpload 
          onUpload={handleUpload} 
          onClose={() => setIsUploadOpen(false)} 
        />
      )}
    </Layout>
  );
};

export default App;
